	('20593041-d605-4174-8404-4b152041eece', '7a162523-1120-4fb9-b291-dfb606c8f1d4', 'Derecho', 'LDER', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Licenciatura'),
	('170f14c6-1b9f-49a7-92f0-ccf79c41d750', '7a162523-1120-4fb9-b291-dfb606c8f1d4', 'Derecho Financiero', 'MDF', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Maestría'),
	('86a8d3ba-99fb-4e67-a03b-ce2c02d36db9', '7a162523-1120-4fb9-b291-dfb606c8f1d4', 'Derecho de Empresa', 'MDE', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Maestría'),
	('6d086d1b-aaea-4b76-9b16-fa8f3e29d9fa', 'a977a640-709d-47d7-a306-9acbe4a867a9', 'Educación Primaria', 'LEPR', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Licenciatura'),
	('e7b89d58-6b55-4993-a96f-bb4eb8c2eb88', 'a977a640-709d-47d7-a306-9acbe4a867a9', 'Ciencias de la Educación', 'LCE', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Licenciatura'),
	('b4e0ad06-84b0-40fc-8228-a75b0c9cbd9b', 'a977a640-709d-47d7-a306-9acbe4a867a9', 'Pedagogía', 'LPED', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Licenciatura'),
	('991edcde-b77e-4d22-b76b-3bf6ec3d3555', 'd17b19c6-b7ab-4bdc-8bb9-ddf6f9e0358e', 'Químico Farmacéutico Biólogo', 'QFB', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Licenciatura'),
	('7075d507-6404-4b18-a5cb-e07a187bae55', '45a6da79-1e2d-4854-9953-6229f46c8e82', 'Mercadotecnia', 'LMER', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Licenciatura'),
	('8f1ce751-949b-45dd-8e38-e10c64b077fd', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Ingeniería Cibernética y Sistemas Computacionales', 'LICS', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-04-28 17:49:58.470598+00', 'Licenciatura'),
