INSERT INTO "public"."estructuras_asignatura" ("id", "nombre", "definicion", "creado_en", "actualizado_en", "template_id", "tipo") VALUES
	('7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'Asignatura SEP/ULSA (semilla)', '{"type": "object", "required": ["denominacion_de_la_asignatura_o_unidad_de_aprendizaje", "ciclo", "clave_de_la_asignatura", "fines_de_aprendizaje_o_formacion", "contenido", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico", "actividades_de_aprendizaje_independientes", "criterios_de_evaluacion", "modalidades_tecnologicas_e_informaticas"], "properties": {"ciclo": {"type": "string", "title": "Ciclo", "examples": ["Primer semestre"], "description": "Indicar el ciclo en el que se impartirá la asignatura en el orden establecido en el mapa curricular. En caso de ser flexible; indicar el área o módulo al que pertenece. Para currículum rígido que contemple asignaturas optativas; indicar “Optativa”, y en caso de que se curse en un ciclo determinado, señalar el ciclo acompañado de la leyenda “Optativa”."}, "contenido": {"type": "null", "const": null, "title": "Contenido temático", "x-column": "contenido_tematico", "description": "Enunciar, en idioma español, los temas y subtemas que se abordarán en la asignatura o unidad de aprendizaje; estructurados de manera lógica y secuencial y numerados en orden jerárquico. Éstos deberán ser acordes con la carga horaria asignada, sustentar la denominación de la asignatura y contribuir al logro de los fines de aprendizaje."}, "clave_de_la_asignatura": {"type": "string", "title": "Clave de la asignatura", "examples": ["MAT-101"], "description": "Anotar la clave que identifica a la asignatura o unidad de aprendizaje; la cual debe coincidir con la señalada en el mapa curricular."}, "criterios_de_evaluacion": {"type": "string", "title": "Criterios de evaluación", "x-column": "criterios_de_evaluacion", "description": "Enlistar las actividades o productos que considerarán para valorar los aprendizajes logrados por los estudiantes, señalar el porcentaje para cada uno, de tal manera que sumen el 100%. Éstos deberán ser acordes con las actividades de aprendizaje."}, "fines_de_aprendizaje_o_formacion": {"type": "string", "title": "Fines de aprendizaje o formación", "description": "Describir los aprendizajes y fines que alcanzará el estudiante al concluir la asignatura. Deberá sustentar la denominación de la asignatura, vincularse con los contenidos temáticos y coadyuvar al logro del fin de aprendizaje y perfil de egreso del plan de estudios."}, "modalidades_tecnologicas_e_informaticas": {"type": "string", "title": "Modalidades tecnológicas e informáticas", "description": "Describir los recursos tecnológicos y de comunicación que se emplearán para el desarrollo del proceso de enseñanza-aprendizaje de la asignatura. Para las modalidades no escolarizada y mixta, este elemento es obligatorio."}, "actividades_de_aprendizaje_independientes": {"type": "string", "title": "Actividades de aprendizaje independientes", "description": "Señalar las actividades de aprendizaje que desarrollará el estudiante de manera independiente. Éstas deberán ser acordes con la naturaleza de la asignatura y la modalidad educativa."}, "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": {"type": "string", "title": "Denominación de la asignatura o unidad de aprendizaje", "examples": ["Matemáticas I"], "description": "Señalar el nombre de la asignatura o unidad de aprendizaje de igual manera que en el mapa curricular."}, "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": {"type": "string", "title": "Actividades de aprendizaje bajo conducción de un académico", "description": "Señalar las actividades de aprendizaje que desarrollará el estudiante en las horas-clase. Éstas deberán ser acordes con la naturaleza de la asignatura, modalidad educativa e instalaciones empleadas, además de contribuir al logro de los fines de aprendizaje."}}, "additionalProperties": false}', '2026-01-09 13:45:37.784586+00', '2026-03-20 23:45:20.582675+00', '1373944894291796699', 'CURRICULAR');
INSERT INTO "public"."estructuras_plan" ("id", "nombre", "tipo", "template_id", "definicion", "creado_en", "actualizado_en") VALUES
	('69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Plan base SEP/ULSA (2026)', 'CURRICULAR', '1373945625988937236', '{"type": "object", "required": ["nombre_autorizado_de_la_institucion", "nivel_y_nombre_del_plan_de_estudios", "modalidad_educativa", "vigencia", "antecedente_academico", "area_de_estudio", "clave_del_plan_de_estudios", "diseno_curricular", "total_de_ciclos_del_plan_de_estudios", "duracion_del_ciclo_escolar", "carga_horaria_a_la_semana", "fines_de_aprendizaje_o_formacion", "perfil_de_egreso", "programa_de_investigacion", "curso_propedeutico", "perfil_de_ingreso", "administracion_y_operatividad_del_plan_de_estudios", "sustento_teorico_del_modelo_curricular", "justificacion_de_la_propuesta_curricular", "propuesta_de_evaluacion_periodica_del_plan_de_estudios", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios"], "properties": {"vigencia": {"type": "string", "title": "Vigencia", "examples": ["2024-2029"], "description": "(Espacio para uso exclusivo de la autoridad educativa)", "referencia_normativa": "Dato administrativo del Anexo 1."}, "area_de_estudio": {"type": "string", "title": "Área de estudio", "examples": ["Ingeniería, industria y construcción", "Ciencias sociales y derecho"], "description": "Señalar el “campo amplio” al que pertenece el plan de estudios. Para ello, considerar la Clasificación Mexicana de Planes de Estudio por Campos de Formación Académica (CMPE 2016), publicado por INEGI.", "referencia_normativa": "Deberá vincularse con el fin de aprendizaje y perfil de egreso del plan de estudios."}, "perfil_de_egreso": {"type": "string", "title": "Perfil de egreso", "examples": ["El egresado será capaz de diseñar estrategias legales..."], "description": "Describir los atributos que habrán desarrollado los estudiantes al concluir el plan de estudios, acordes al nivel educativo y denominación propuesta. De preferencia, dividirlo en conocimientos, habilidades y actitudes.", "referencia_normativa": "Corresponde al requisito ''Perfil de egreso'' del Artículo 8, fracción VI del Acuerdo 17/11/17."}, "diseno_curricular": {"enum": ["Rígido", "Flexible"], "type": "string", "title": "Diseño curricular", "examples": ["Flexible"], "description": "Indicar si es “Rígido” o “Flexible”.", "referencia_normativa": "Define la estructura para el requisito ''Mapa curricular'' del Artículo 8, fracción VII del Acuerdo 17/11/17."}, "perfil_de_ingreso": {"type": "string", "title": "Perfil de ingreso", "examples": ["Conocimientos básicos de matemáticas, capacidad de análisis y redacción."], "description": "Indicar las condiciones académicas ideales (conocimientos, habilidades y aptitudes), para incorporarse al plan de estudios. Deberá vincularse con el nivel educativo y campo de estudio.", "referencia_normativa": "Corresponde al requisito ''Perfil de ingreso'' (condiciones mínimas requeridas) del Artículo 8, fracción V del Acuerdo 17/11/17."}, "curso_propedeutico": {"type": ["string", "null"], "title": "Curso propedéutico", "examples": ["Curso de nivelación de 40 horas obligatorio para aspirantes de áreas ajenas."], "description": "Señalar las situaciones en las que aplicará el curso propedéutico, la población a la que estará dirigido, su duración, la relación con el plan de estudios, así como la información que considere relevante.", "referencia_normativa": "Elemento opcional mencionado en las guías de llenado del Anexo 1."}, "modalidad_educativa": {"enum": ["Escolar", "No escolarizada", "Mixta"], "type": "string", "title": "Modalidad educativa", "examples": ["Escolar"], "description": "Señalar la modalidad educativa en la que se impartirá el plan de estudios: escolar, no escolarizada o mixta.", "referencia_normativa": "Corresponde al requisito de ''Modalidad educativa'' del Artículo 8, fracción II del Acuerdo 17/11/17."}, "antecedente_academico": {"type": "string", "title": "Antecedente académico", "examples": ["Bachillerato concluido o equivalente.", "Título de Licenciatura en áreas afines a la salud."], "description": "Señalar el nivel educativo requerido para ingresar al plan de estudios. Para posgrados, además del nivel educativo; indicar la(s) disciplina(s) o área(s) afín(es) al plan de estudios.", "referencia_normativa": "Corresponde al requisito ''Perfil de ingreso'' (antecedente académico necesario) del Artículo 8, fracción V del Acuerdo 17/11/17."}, "carga_horaria_a_la_semana": {"type": "number", "title": "Carga horaria a la semana", "examples": [25], "description": "Indicar la máxima carga horaria impartida a la semana; no mayor a 50 horas bajo la conducción de un académico.", "referencia_normativa": "Corresponde a la restricción ''sin exceder una carga máxima de 50 horas efectivas por semana'' del Artículo 8, fracción III del Acuerdo 17/11/17."}, "programa_de_investigacion": {"type": ["string", "null"], "title": "Programa de investigación", "examples": ["Línea 1: Innovación Educativa. Objetivo: Analizar el impacto de..."], "description": "(Obligatorio para el nivel de Doctorado y para aquéllas Maestrías orientadas a la investigación). Presentar el programa de investigación que describa los objetivos del programa y líneas de investigación con sus respectivos objetivos. Asimismo, detallar la vinculación con las asignaturas que conforman el plan de estudios, la metodología y presentación de las investigaciones, así como el perfil de los docentes que guiarán su desarrollo.", "referencia_normativa": "Requisito obligatorio solo para Doctorados o Maestrías con orientación a investigación según el Artículo 10, fracción III incisos b) y c) del Acuerdo 17/11/17."}, "clave_del_plan_de_estudios": {"type": "string", "title": "Clave / Año del plan", "examples": ["2024"], "description": "Señalar el año en el que solicita el trámite.", "referencia_normativa": "Dato administrativo del Anexo 1."}, "duracion_del_ciclo_escolar": {"type": "string", "title": "Duración mínima en semanas de cada ciclo escolar", "examples": ["16 semanas"], "description": "Señalar el número mínimo de semanas efectivas de clase que integran el tipo de ciclo en el que se imparte el plan de estudios.", "referencia_normativa": "Corresponde exactamente al requisito ''Duración mínima en semanas'' del Artículo 8, fracción III del Acuerdo 17/11/17."}, "fines_de_aprendizaje_o_formacion": {"type": "string", "title": "Fin de aprendizaje o formación", "examples": ["El estudiante analizará los principios fundamentales del derecho penal..."], "description": "Describir los aprendizajes que lograrán los estudiantes al concluir el plan de estudios. Deberá corresponder con el nivel educativo y la denominación del plan de estudios.", "referencia_normativa": "Corresponde al requisito ''Descripción de los fines del aprendizaje o formación'' del Artículo 8, fracción IV del Acuerdo 17/11/17."}, "nivel_y_nombre_del_plan_de_estudios": {"type": "string", "title": "Nivel y nombre del plan de estudios", "examples": ["Licenciatura en Derecho", "Maestría en Ciencias de la Computación"], "description": "Indicar el nivel educativo y denominación del plan de estudios.", "referencia_normativa": "Corresponde al requisito ''Nivel y denominación del plan de estudios'' del Artículo 8, fracción I del Acuerdo 17/11/17."}, "nombre_autorizado_de_la_institucion": {"type": "string", "title": "Nombre autorizado de la institución", "examples": ["Universidad La Salle A.C."], "description": "Proporcionar el nombre de la institución autorizado por SEP.", "referencia_normativa": "Dato administrativo del Anexo 1."}, "total_de_ciclos_del_plan_de_estudios": {"type": "string", "title": "Número de ciclos escolares que integrarán el plan de estudio", "examples": ["9 cuatrimestres", "8 semestres"], "description": "En diseño flexible especificar mínimo y máximo de ciclos. En diseño rígido especificar el total de ciclos.", "referencia_normativa": "Corresponde a ''señalando el número de ciclos en que se impartirá'' del Artículo 8, fracción III del Acuerdo 17/11/17."}, "sustento_teorico_del_modelo_curricular": {"type": ["string", "null"], "title": "Sustento teórico del modelo curricular", "examples": ["Modelo por competencias profesionales fundamentado en el constructivismo..."], "description": "Presentar de forma concreta el marco conceptual en el que se justifica y fundamenta el diseño y organización curricular del plan de estudios.", "referencia_normativa": "Corresponde al ''sustento teórico del modelo curricular'' que el particular puede incluir según el Artículo 8 (párrafo tercero) del Acuerdo 17/11/17."}, "justificacion_de_la_propuesta_curricular": {"type": ["string", "null"], "title": "Justificación de la propuesta curricular en la modalidad no escolarizada o mixta", "examples": ["Se utilizará una plataforma LMS asincrónica complementada con sesiones síncronas..."], "description": "(Exclusivo para modalidades no escolarizada y mixta). Describir cómo se impartirá el plan de estudios en la modalidad educativa elegida, los recursos tecnológicos y/o didácticos que emplearán para su desarrollo y su vinculación con las asignaturas y actividades de aprendizaje.", "referencia_normativa": "Corresponde a lo solicitado en el Artículo 14 (justificación de modalidad) y Artículo 15 (especificaciones de plataforma/modelo) del Acuerdo 17/11/17."}, "administracion_y_operatividad_del_plan_de_estudios": {"type": ["string", "null"], "title": "Administración y operatividad del plan de estudios", "examples": ["El estudiante podrá inscribir un mínimo de 3 y un máximo de 6 asignaturas por ciclo..."], "description": "Describir la administración del plan de estudios, así como su operatividad; considerando el tipo de diseño curricular empleado. Si es flexible; incorporar el número mínimo y máximo de asignaturas que se cursarán por ciclo.", "referencia_normativa": "Corresponde a la ''descripción detallada de la(s) forma(s) de administración y operatividad'' permitida en el Artículo 8 (párrafo tercero) del Acuerdo 17/11/17."}, "propuesta_de_evaluacion_periodica_del_plan_de_estudios": {"type": ["string", "null"], "title": "Propuesta de evaluación periódica del plan de estudios", "examples": ["Revisión quinquenal mediante encuestas a empleadores, egresados y análisis de tendencias del mercado."], "description": "Describir de manera detallada la metodología que emplearán para la evaluación del plan de estudios, incluyendo los instrumentos y periodicidad en la que se llevará a cabo; con la finalidad de mantenerlo actualizado y acorde a las necesidades educativas y disciplinares.", "referencia_normativa": "Corresponde al requisito ''Propuesta de evaluación periódica del Plan de estudio'' del Artículo 8, fracción VIII del Acuerdo 17/11/17."}, "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": {"type": "string", "title": "Nombre y cargo de la persona facultada para autorizar el plan de estudios", "examples": ["Dr. Juan Pérez Gómez, Rector de la Universidad XYZ"], "description": "Indicar el nombre y cargo de la persona facultada para autorizar el plan de estudios.", "referencia_normativa": "Dato administrativo del Anexo 1."}}, "additionalProperties": false}', '2026-01-09 13:45:37.784586+00', '2026-03-20 23:45:37.03127+00');
INSERT INTO "public"."usuarios_app" ("id", "nombre_completo", "email", "externo", "creado_en", "actualizado_en") VALUES
	('11111111-1111-1111-1111-111111111111', 'Alejandro Rosales', 'alejandro.rosales@lasalle.mx', false, '2026-01-09 13:45:37.784586+00', '2026-01-09 13:45:37.784586+00'),
	('22222222-2222-2222-2222-222222222222', 'Profesora OffSec', 'offsec@lasalle.mx', false, '2026-01-09 13:45:37.784586+00', '2026-01-09 13:45:37.784586+00');
INSERT INTO "public"."planes_estudio" ("id", "carrera_id", "estructura_id", "nombre", "tipo_ciclo", "numero_ciclos", "datos", "estado_actual_id", "activo", "tipo_origen", "meta_origen", "creado_por", "actualizado_por", "creado_en", "actualizado_en") VALUES
	('335ce0a7-048c-4fb5-820e-2eb4a156b3fa', '76224caa-1203-4b18-b9df-758f1f9a97fb', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería Biomédica', 'Semestre', 8, '{"vigencia": "", "area_de_estudio": "Ingeniería Biomédica", "perfil_de_egreso": "Al término de la Licenciatura, los egresados serán capaces de:  \n· Vincular conocimientos fundamentales de matemáticas, ciencias básicas, informática, ingeniería y medicina desde el ámbito de la ingeniería biomédica, para incidir en la calidad de los servicios del Sistema de Salud.\n· Coadyuvar en el diseño y la adaptación de equipos y sistemas para la salud, así como en la innovación y conservación de la tecnología médica para la atención integral de la población.\n· Seleccionar, transformar, conservar y producir dispositivos tales como instrumentos, equipos, aparatos o accesorios diversos para el eficiente funcionamiento del proceso de atención a la salud, contribuyendo a la preservación del medio ambiente.\n· Participar, bajo principios éticos, en el diseño de unidades físicas de atención a la salud, así como en la elaboración de la normatividad técnica para su construcción y equipamiento, estableciendo criterios y estándares óptimos que apoyen la gestión sostenible de recursos.\n· Aplicar técnicas de procesamiento de señales e imágenes, para coadyuvar en el diagnóstico médico y en la telemedicina.\n· Colaborar en la administración de la informática médica, considerando estándares nacionales e internacionales, para el aprovechamiento integral de recursos de entidades nosológicas.\n· Administrar la tecnología biomédica considerando su planeación, adquisición, mantenimiento y evaluación para mejorar la eficiencia y eficacia de la atención a la salud.\n· Dirigir las áreas de ingeniería biomédica de instituciones hospitalarias aplicando técnicas modernas y vinculando acciones administrativas, médicas y de mejora.\n· Asesorar y participar en la capacitación de los usuarios para el manejo adecuado de la tecnología biomédica.\n· Interactuar de manera profesional y ética con el personal que brinda los servicios de salud, proponiendo soluciones multidisciplinarias en el campo de la ingeniería biomédica con actitud de cooperación y respeto.\n· Diseñar y gestionar proyectos vinculados a su desarrollo profesional ocupacional, con actitud emprendedora e innovadora, bajo un enfoque de sustentabilidad y de responsabilidad social, a partir del trabajo multidisciplinar y colaborativo, considerando las características de la sociedad actual a nivel local y global.\n· Incorporar en su práctica profesional, la utilización de estrategias de autorregulación y comunicación eficaz en español e inglés, así como las TIC como herramientas para la gestión de información y la actualización permanente en su campo disciplinar, con el fin de favorecer el intercambio de ideas en contextos multidisciplinarios tanto académicos como profesionales.\n· Consolidar una actitud de respeto y valoración por sí mismo, los demás y diversas culturas incluida la propia, así como contraer un compromiso de servicio a nivel personal y profesional hacia la sociedad actual, a partir de la reflexión y definición de sus posturas con respecto a los valores trascendentes de la existencia humana.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Es recomendable que el interesado en estudiar la Licenciatura en Ingeniería Biomédica cuente con las siguientes características:  \nAntecedentes Académicos  \n· Preferentemente haber cursado el área de físico-matemáticas de bachillerato\n\nConocimientos  \n· Física y matemáticas preuniversitarias\n\nDisposición para (habilidades y destrezas):  \n· El pensamiento lógico-analítico  \n· El pensamiento convergente y divergente  \n· La interpretación abstracta de la realidad\n\nDisposición para (habilidades y destrezas):  \n· El trabajo colaborativo y multidisciplinario  \n· La solución de problemas desde una perspectiva reflexiva y lógico-matemática  \n· El manejo de herramientas, máquinas, materiales y equipos  \n· La construcción de soluciones que integren tecnologías, con el apoyo de herramientas computacionales\n\nActitudes y Valores  \n· Sensibilidad por los problemas y necesidades de la sociedad  \n· Consideración de principios éticos y de respeto  \n· Responsabilidad y autodisciplina  \n· Perspectiva comunitaria.", "curso_propedeutico": null, "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato o equivalente", "carga_horaria_a_la_semana": 50, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2013", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Formar profesionistas con saberes, habilidades, actitudes y valores que les permitan incursionar en las diferentes ramas de la profesión, a través de la innovación, aplicación y administración de soluciones tecnológicas viables que coadyuven a mejorar la atención médica de la población; e interactuar en equipos multidisciplinarios para incidir en la calidad de los servicios del Sistema de Salud, todo ello sustentado en principios científicos, bioéticos y humanistas.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Biomédica", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": null, "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": null, "propuesta_de_evaluacion_periodica_del_plan_de_estudios": null, "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "MTRO. MARIO ALEJANDRO OLIVARES PORRAZ, SUBDIRECTOR DE RECONOCIMIENTO, DIRECCIÓN DE INSTITUCIONES PARTICULARES DE EDUCACIÓN SUPERIOR, S.E.P."}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"referencias": {"archivoWordOpenAI": "file-LTjfivcVJbQ9SSxZXJRogV"}, "generado_por": "ai-generate-plan", "clonacionPlan": true}', NULL, NULL, '2026-04-30 18:26:33.863856+00', '2026-04-30 18:26:33.863856+00'),
	('198c763b-9d97-423b-b13a-5713437fc81b', '6d086d1b-aaea-4b76-9b16-fa8f3e29d9fa', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Educación Especial como sombra', 'Semestre', 9, '{"vigencia": "(Espacio para uso exclusivo de la autoridad educativa)", "area_de_estudio": "Formación docente y ciencias de la educación", "perfil_de_egreso": "Conocimientos:\n  - Marco conceptual de la Educación Especial y modelos de atención a la diversidad.\n  - Normativa nacional e internacional sobre inclusión educativa y derechos de las personas con discapacidad.\n  - Características del desarrollo infantil y del aprendizaje en educación primaria.\n  - Estrategias pedagógicas y adaptaciones curriculares para diversas necesidades educativas.\nHabilidades:\n  - Identificar y diagnosticar barreras de aprendizaje en entornos escolares.\n  - Diseñar y aplicar adaptaciones curriculares y estrategias de apoyo individualizado.\n  - Intervenir como figura de sombra para facilitar la participación y el aprendizaje en aula regular.\n  - Colaborar con equipos docentes, familias y profesionales para la elaboración de planes de atención individualizada.\n  - Evaluar el progreso del estudiante mediante instrumentos cualitativos y cuantitativos.\nActitudes:\n  - Promover una práctica profesional ética, centrada en la dignidad y derechos del estudiantado.\n  - Mostrar sensibilidad hacia la diversidad cultural, funcional y socioemocional.\n  - Adoptar una postura reflexiva, colaborativa y comprometida con la mejora continua.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Conocimientos previos:\n  - Educación media superior (bachillerato) completada.\n  - Conocimientos básicos de psicología del desarrollo y didáctica (preferente).\nHabilidades y destrezas:\n  - Capacidad de comunicación clara y trabajo en equipo.\n  - Habilidad para la observación y registro de conductas y procesos de aprendizaje.\n  - Manejo básico de herramientas informáticas (navegación web, edición de texto y acceso a plataformas educativas).\nAptitudes personales:\n  - Vocación por el trabajo con infancia y jóvenes.\n  - Paciencia, tolerancia y resiliencia para la resolución de conflictos en entornos escolares.\n  - Disponibilidad para realizar estancias prácticas en centros educativos y trabajo de campo.", "curso_propedeutico": "Situaciones de aplicación:\n  - Dirigido a aspirantes que no acrediten formación previa en áreas afines (psicopedagogía, educación o trabajo social).\nPoblación objetivo:\n  - Aspirantes a la licenciatura con bachillerato completo.\nDuración y estructura:\n  - 40 horas (presenciales o en modalidad mixta), organizado en 4 módulos.\nRelación con el plan de estudios:\n  - Introduce fundamentos del desarrollo infantil, terminología de inclusión y manejo básico de registros y observación; prepara para las prácticas iniciales.", "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato concluido (Certificado de educación media superior). Se valorará experiencia previa en entornos educativos o comunitarios; no es requisito excluyente.", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "LLSE-2026", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": " - Analizar los fundamentos teóricos y normativos de la Educación Especial y la atención a la diversidad.\n - Diagnosticar necesidades educativas individuales mediante técnicas de observación y evaluación formativa.\n - Diseñar intervenciones pedagógicas y adaptaciones curriculares orientadas a la inclusión en educación primaria.\n - Implementar estrategias de mediación y apoyo individual (figura de sombra) para facilitar la participación y el aprendizaje.\n - Colaborar con equipos docentes y familias para la planificación y seguimiento de planes de atención individualizada.\n - Evaluar el impacto de las estrategias de apoyo e intervenir de forma reflexiva para su mejora continua.\n - Promover prácticas profesionales éticas y respeto a los derechos de las personas con discapacidad.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura - Licenciatura en Educación Especial (énfasis: figura de sombra para educación primaria)", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9 ciclos semestrales", "sustento_teorico_del_modelo_curricular": "Lista de pasos conceptuales previos a la elaboración:\n  - Revisar requisitos normativos del Acuerdo 17/11/17 y correspondencia con ciclos semestrales.\n  - Definir perfil de egreso alineado con competencias profesionales para la figura de sombra.\n  - Estructurar asignaturas y prácticas que integren teoría, práctica reflexiva y colaboración interprofesional.\n\nMarco conceptual y fundamentos:\n  - Enfoque por competencias: El plan articula saberes, capacidades y actitudes necesarias para la práctica profesional en entornos inclusivos.\n  - Constructivismo social y aprendizaje situado: Se privilegia el aprendizaje contextualizado en aula y en comunidad, con énfasis en la observación y la práctica asistida.\n  - Diseño Universal para el Aprendizaje (DUA): Fundamenta la propuesta de adaptaciones curriculares y estrategias de accesibilidad.\n  - Enfoque de derechos humanos e inclusión educativa: La intervención pedagógica se orienta a garantizar la participación plena y no discriminación.\n  - Investigación-acción y reflexión profesional: Los practicantes desarrollan competencias para investigar su propia práctica y ajustar intervenciones.\n\nVinculación curricular:\n  - Las asignaturas teóricas, metodológicas y las prácticas profesionales se articulan para desarrollar progresivamente la capacidad de intervenir como sombra, evaluar necesidades y coordinar apoyos.", "justificacion_de_la_propuesta_curricular": "Descripción de la modalidad mixta y recursos tecnológicos:\n  - La modalidad mixta combina sesiones presenciales para talleres y prácticas de campo, con componentes virtuales para contenidos teóricos, seminarios y tutorías.\n  - Plataforma educativa: Uso de un LMS institucional (por ejemplo, Moodle o Canvas) para entregar contenidos asincrónicos, foros académicos, rúbricas y actividades de evaluación.\n  - Herramientas sincrónicas: Videoconferencias para seminarios, supervisión de prácticas y sesiones de retroalimentación (Zoom/Teams integradas al LMS).\n  - Recursos didácticos: Banco de recursos multimedia, casos clínicos, simulaciones y módulos interactivos para el desarrollo de competencias de observación y diseño de adaptaciones.\nAutogestión y flexibilidad espacio-temporal:\n  - Los estudiantes disponen de materiales asincrónicos que permiten avanzar de manera flexible, con itinerarios de estudio y fechas de entrega acotadas.\n  - Se garantiza acompañamiento mediante tutorías periódicas (individuales y grupales) y supervisión de prácticas en campo.\nVinculación con actividades de aprendizaje:\n  - Las asignaturas incluyen actividades de observación estructurada en aulas, prácticas acompañadas en centros educativos, diseño y aplicación de adaptaciones y proyectos integradores.\n  - La plataforma registra evidencias de aprendizaje (portafolio digital) y facilita la evaluación formativa por parte de docentes y supervisores de práctica.", "administracion_y_operatividad_del_plan_de_estudios": "Estructura administrativa y académica:\n  - Dirección Académica: Responsable general del programa y de la vinculación institucional.\n  - Coordinación de la Licenciatura: Gestión curricular, seguimiento a planes de estudio y coordinación de prácticas.\n  - Cuerpo académico: Perfil con experiencia en educación especial, psicopedagogía y práctica escolar inclusiva; se exige formación de posgrado preferente y experiencia en supervisión de prácticas.\n  - Tutoría académica: Sistema de tutorías para seguimiento individual del estudiante y acompañamiento en estancias prácticas.\nOperatividad del calendario y carga por ciclo:\n  - Diseño rígido: 9 semestres obligatorios.\n  - Asignaturas por semestre (típico): 5 a 6 asignaturas, combinando teoría, metodología y práctica; una asignatura práctica o de taller por semestre como mínimo.\n  - Estancias y prácticas: Prácticas progresivas con incremento de horas en los semestres superiores y prácticas intensivas de intervención en escuela en los últimos semestres.\nGestión de calidad y recursos:\n  - Espacios formativos: Aulas, laboratorios didácticos, centro de observación y convenios con escuelas de educación primaria para estancias.\n  - Recursos humanos: Profesores con perfil docente-investigador y supervisores de práctica con formación en educación especial.\n  - Documentación operativa: Manuales de práctica, rúbricas de evaluación, convenios de colaboración y normativa interna para el desarrollo de estancias.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Metodología e instrumentos:\n  - Evaluación cuatrienal interna con revisión anual de resultados: combinación de análisis de indicadores cuantitativos y cualitativos.\n  - Instrumentos: Encuestas a egresados y empleadores, informe de seguimiento de egresados (tracer study), evaluación de desempeño de estudiantes en prácticas, análisis de cargas y resultados académicos, reuniones del Comité Académico.\n  - Periodicidad: Revisión anual de indicadores clave (retención, titulación, desempeño en prácticas), evaluación curricular cada tres años para ajustes mayores.\n  - Participación de actores: Voces de estudiantes, egresados, docentes, escuelas vinculadas y sociedad civil en foros de evaluación.\n  - Mecanismos de mejora: Planes de acción derivados de la evaluación, actualización de asignaturas, capacitación docente y revisión de convenios de práctica.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "No considerar específicamente el TDA si no todas las posibilidades de la educación especial, incluyendo discapacidades", "descripcionEnfoqueAcademico": "Una carrera relacionada con la educación especial, relacionada con la figura de sombra para educación primaria, y educación especial para personas con TDA"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai-generate-plan"}', NULL, NULL, '2026-02-27 22:23:03.864946+00', '2026-04-28 17:49:58.470598+00'),
	('4660b774-a6e2-44f4-a340-747b41235c7c', '089cdeda-d557-4a57-b49f-eb44921dfa3a', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería en Sistemas Domóticos (2027)', 'Semestre', 9, '{"nivel": "Bachillerato", "nombre": "Especialización en Gravedad Cuántica de Bucles", "area_de_estudio": "Ciencias Físico-Matemáticas", "perfil_de_egreso": "La Specialización en Gravedad Cuántica de Bucles formará a un especialista capaz de integrar creativamente conocimientos avanzados en física, matemáticas y computación para enfrentar problemas teóricos y fenomenológicos en la intersección de la relatividad general y la mecánica cuántica. Al finalizar el programa, el egresado será capaz de: 1) Comprender y aplicar los fundamentos de la gravedad cuántica de bucles, incluyendo su formulación canónica, las variables de Ashtekar y el formalismo de redes de espín; 2) Desarrollar modelos y simulaciones rigurosas de fenómenos cuántico-gravitacionales, empleando métodos numéricos y herramientas de cómputo científico para analizar redes y espumas de espín, así como su relación con la cosmología cuántica; 3) Utilizar y conectar conceptos avanzados de geometría diferencial, teoría de grupos de Lie, representaciones y espinores para la construcción de estados cuánticos geométricos; 4) Resolver y comunicar de manera crítica problemas de frontera en física teórica contemporánea, integrando procesos de modelado matemático, análisis computacional y validación fenomenológica; 5) Evaluar y proponer soluciones innovadoras en entornos de trabajo colaborativo, mostrando habilidad para desarrollar proyectos científicos reproducibles bajo principios éticos y de buenas prácticas en la investigación; 6) Integrarse a comunidades científicas y continuar con estudios de posgrado o desempeñarse en entornos interdisciplinares que involucren física matemática, simulación, cosmología, información cuántica o modelado de sistemas complejos.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "El aspirante debe haber concluido el bachillerato con perfil Área 1 (Ciencias Físico-Matemáticas), lo que implica sólidas bases en matemáticas, física, química, razonamiento lógico y competencia en análisis de problemas. Se espera capacidad para el aprendizaje autónomo y familiaridad con herramientas y conceptos científicos y tecnológicos, así como interés en la resolución de problemas complejos y trabajo experimental.", "curso_propedeutico": "No tiene", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato en Ciencias Físico-Matemáticas, con orientación en matemáticas y física; requisito previo para ingreso a la especialización. El plan asume que el aspirante ha concluido un bachillerato con áreas de Ciencias Físico-Matemáticas.", "carga_horaria_a_la_semana": 27, "programa_de_investigacion": "No aplica", "clave_del_plan_de_estudios": "2020", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Analizar fundamentos de la gravedad cuántica de bucles y su relación con la relatividad general; Diseñar modelos computacionales para explorar redes de espín y espumas cuánticas, con enfoque en cosmología cuántica; Evaluar resultados numéricos mediante criterios de reproducibilidad y validación fenomenológica; Comunicar resultados científicos de forma clara, estructurada y técnica; Integrar conceptos de domótica, electrónica, control y sistemas computacionales mediante herramientas de simulación para proyectos interdisciplinarios y el desarrollo de asistentes virtuales; Aplicar herramientas de cómputo para la creación de proyectos con código reproducible y documentación adecuada; Desarrollar capacidades de trabajo en equipo, ética científica y buenas prácticas en investigación.", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "No aplica", "justificacion_de_la_propuesta_curricular": "No aplica", "administracion_y_operatividad_del_plan_de_estudios": "La administración y operatividad del plan de estudios se ubica bajo la Dirección de Asuntos Académicos - Anexo 1; modalidad escolar; estructura rígida con 9 ciclos; carga horaria semanal de 27 horas; responsable: Lic. María González Pérez, Directora Académica; procesos de revisión y actualización conforme a la Propuesta de Evaluación Periódica y a los lineamientos del Acuerdo 17/11/17.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Nivel de evaluación curricular interna: diagnóstico de estructura y operación. Análisis técnico-pedagógico del planteamiento curricular vigente; consulta a directivos del área académica para valorar problemáticas de formación y operación; consulta a docentes sobre problemáticas de formación, operación y necesidades disciplinarias; estudio de opinión de estudiantes sobre la formación y operación. Nivel de evaluación curricular externa: diagnóstico de impacto y prácticas profesionales. Análisis del estado del conocimiento en campos disciplinarios vinculados al programa, comparación de planes y tendencias en criterios de organismos evaluadores; estudio con egresados y empleadores para valorar inserción laboral y requerimientos actuales; recopilación de criterios y reformas necesarias para mantener el programa actualizado y acorde con la disciplina."}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "notasAdicionales": "Agrega a los asistentes virtuales", "descripcionEnfoque": "Carrera relacionada con la domótica, electrónica, control y sistemas computacionales"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 9812, "total_tokens": 19204, "output_tokens": 9392, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 8256}}, "responseId": "resp_0b1339b15ea08d51006973b4892a20819c954b7fe00a35e1ed", "conversationId": null}}', NULL, NULL, '2026-01-23 17:50:00.85346+00', '2026-04-28 17:49:58.470598+00'),
	('c90aebbb-454e-4a8e-b2a3-99dd1c200e86', '8208da08-d549-4359-8865-9d806bc54f19', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería en Cibernética y Ciberseguridad (2026)', 'Semestre', 9, '{"nivel": "Licenciatura", "nombre": "Ingeniería Cibernética y Ciberseguridad", "area_de_estudio": "5. Ingeniería, manufactura y construcción (CMPE 2016)", "perfil_de_egreso": "Al finalizar, el egresado demostrará los siguientes atributos: Conocimientos Fundamentos de matemáticas, física y probabilidad aplicados a señales, control y comunicaciones. Arquitecturas de redes, sistemas operativos, virtualización, servicios en la nube e integración TI/OT. Modelado y control de sistemas ciberfísicos y embebidos, protocolos industriales e IoT. Criptografía aplicada, gestión de identidades, gobierno y gestión de seguridad de la información. Normativa y marcos de referencia: ISO/IEC 27001/27002, NIST CSF/800-53, MITRE ATT&CK, OWASP, ENS (referencial), legislación mexicana aplicable en protección de datos y delitos informáticos. Auditoría de seguridad, pruebas de penetración éticas, respuesta a incidentes y continuidad del negocio. Gestión de proyectos, economía de la ciberseguridad y ética profesional. HabilidadesDiseñar y desplegar arquitecturas seguras para redes, nube y sistemas ciberfísicos. Programar en C/C++, Python y scripts para automatización, pruebas y análisis. Configurar y operar firewalls, IDS/IPS, SIEM, WAF, VPN, segmentación y Zero Trust básico. Conducir análisis de riesgo, planes de tratamiento y auditorías técnicas y de cumplimiento. Orquestar procesos de detección, respuesta y recuperación ante incidentes. Desarrollar prototipos de IoT seguro y realizar hardening de dispositivos embebidos. Comunicar resultados técnicos mediante informes ejecutivos y presentaciones efectivas. Actitudes y valoresÉtica, responsabilidad social y legalidad en el manejo de información y en pruebas de seguridad. Aprendizaje autónomo y actualización permanente. Trabajo colaborativo, liderazgo y orientación a resultados. Respeto a la diversidad, perspectiva de género e inclusión.", "diseno_curricular": "Flexible", "perfil_de_ingreso": " ConocimientosMatemáticas de bachillerato: álgebra, funciones y trigonometría. Ofimática e informática básica; navegación segura en Internet. Inglés técnico básico (lectura de manuales). HabilidadesPensamiento lógico-matemático y resolución de problemas. Comunicación escrita y oral. Gestión del tiempo y aprendizaje autónomo. ActitudesInterés por la tecnología, la seguridad digital y la innovación. Ética, responsabilidad y respeto a la legalidad. Trabajo colaborativo y apertura al aprendizaje continuo.", "curso_propedeutico": "Aplicará cuando el diagnóstico de ingreso identifique brechas en matemáticas y programación. Población: aspirantes provenientes de bachilleratos no afines. Duración: 40 horas (4 semanas).  Contenidos: Aritmética y álgebra para ingeniería; pensamiento lógico; introducción a programación (Python); fundamentos de redes; ciudadanía digital y nociones de ciberseguridad.  Evaluación: examen criterio-referido (70% mínimo) y evidencias prácticas.  Vinculación: articulado con Programación I, Matemáticas I y Fundamentos de Redes.", "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato general o tecnológico concluido, o Técnico Superior Universitario equivalente, preferentemente en áreas físico-matemáticas, informática, electrónica o afines.", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2025", "duracion_del_ciclo_escolar": "18 semanas efectivas por ciclo semestral", "fines_de_aprendizaje_o_formacion": "El plan de estudios se orienta al desarrollo de competencias profesionales para diseñar, implementar y gestionar sistemas ciberfísicos y de ciberseguridad en organizaciones públicas y privadas, con enfoque de resultados y apego normativo. Al concluir, el egresado será capaz de: Analizar arquitecturas de sistemas ciberfísicos, redes y servicios para identificar riesgos, amenazas y vulnerabilidades. Diseñar estrategias de ciberseguridad basadas en estándares (ISO/IEC 27001, NIST, MITRE ATT&CK) y en principios de ingeniería segura. Implementar controles técnicos y administrativos, incluyendo criptografía aplicada, segmentación de redes, endurecimiento de sistemas y gestión de identidades. Programar y modelar sistemas embebidos y de IoT con prácticas de seguridad por diseño. Administrar infraestructuras de TI/OT y plataformas de monitoreo (SIEM, IDS/IPS) para la detección y respuesta a incidentes. Evaluar la conformidad normativa y el riesgo tecnológico mediante auditorías técnicas y de cumplimiento. Integrar metodologías de ciencia de datos e inteligencia artificial para la detección de anomalías y ciberamenazas. Simular, probar y validar el desempeño y la resiliencia de sistemas cibernéticos en entornos controlados (cyber range/laboratorios). Gestionar proyectos tecnológicos aplicando enfoques ágiles y de calidad, con perspectiva ética y de sostenibilidad. Comunicar hallazgos técnicos y recomendaciones a audiencias técnicas y directivas, sustentando decisiones con evidencia.", "total_de_ciclos_del_plan_de_estudios": "8 a 10 ciclos (semestres)", "sustento_teorico_del_modelo_curricular": "Se adopta un  modelo por competencias y resultados de aprendizaje, con base en: Constructivismo y aprendizaje situado para problemas reales.  Taxonomía de Bloom para progresión cognitiva. OBE/ABET para trazabilidad de resultados de programa-asignatura.  CDIO (Concebir-Diseñar-Implementar-Operar) en proyectos integradores. Evaluación auténtica mediante rúbricas y desempeño en laboratorios físicos y virtuales.", "justificacion_de_la_propuesta_curricular": "La  modalidad mixta combina sesiones presenciales/laboratorio y trabajo en línea para garantizar pertinencia, flexibilidad espacio-temporal y autogestión del aprendizaje. Plataformas tecnológicas: LMS institucional (p. ej., Moodle 4.x) con repositorio de contenidos, foros, cuestionarios, rúbricas y analítica; videoconferencia para sesiones sincrónicas; repositorios de código (Git) y laboratorios virtuales (simuladores de redes y ciberseguridad, sandboxes y máquinas virtuales) articulados con las asignaturas. Distribución horaria: 40-60% de horas bajo conducción (presencial o síncrona) y 60-40% de horas independientes (asíncronas) según la naturaleza de cada asignatura. Funcionalidad con instalaciones: laboratorios de redes, ciberseguridad e IoT; cyber range institucional; aulas de cómputo; todos con políticas de seguridad, bitácoras y control de acceso.  Estrategias de aprendizaje: aula invertida, aprendizaje basado en problemas/proyectos, retos de blue/red team, estudios de caso y simulaciones.  Evaluación: tareas prácticas en plataforma, laboratorios verificados, exámenes en línea con supervisión, presentaciones y defensa técnica.  Perfil docente: ingenierías afines con experiencia en TI/OT, certificaciones deseables (CCNA/Network Security, ISO 27001 LA/LI, CEH o equivalentes) y dominio de herramientas LMS.", "administracion_y_operatividad_del_plan_de_estudios": "El plan es de  diseño flexible con seriación académica por competencias y créditos. Se cursa en  8 a 10 semestres con un total referencial de  320 créditos (≥300 conforme al Art. 10). La operación académica considera: Carga por ciclo: de 5 a 7 asignaturas por semestre. Promedio semanal: 18-22 horas bajo conducción y 18-22 horas independientes (carga máxima 40 h/sem).  Modalidad mixta: al menos el 40% de las horas del programa son bajo conducción de un académico (≥960 h totales); el resto en actividades independientes mediadas por plataforma.  Seriación típica: Programación I → Programación II → Estructuras de Datos → Sistemas Operativos; Matemáticas I → Matemáticas II → Probabilidad y Estadística; Redes I → Redes II → Seguridad en Redes; Control I → Sistemas Embebidos → IoT Seguro.  Componentes de formación: básica (matemáticas, ciencias y programación), profesional (redes, sistemas, control, seguridad), terminal optativa (ciberdefensa, forense, nube, OT/SCADA), <i>Proyecto Integrador</i> y <i>Estancia/Residencia</i>.  Tutoría y asesoría: obligatoria el primer año y bajo demanda en cursos superiores.  Servicio social: 480 horas conforme a normativa aplicable.  Acreditación y titulación: por créditos y opción de titulación por examen general, proyecto aplicado, portafolio de evidencias o tesis.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "La evaluación del plan se realizará con una  periodicidad bienal y cortes anuales, mediante: Método: ciclo PDCA con evidencias OBE: mapeo resultados de programa-asignatura, rúbricas, portafolios y KPIs institucionales.  Instrumentos: encuestas a estudiantes y egresados, panel de empleadores, análisis de EGEL/EXANI (cuando aplique), analítica del LMS, informes de prácticas/residencias y auditorías académicas internas.  Indicadores: eficiencia terminal, tiempo de titulación, empleabilidad, resultados de aprendizaje, certificaciones profesionales obtenidas, producción de proyectos y patentes/prototipos.  Vinculación sectorial: Consejo Consultivo con industria (TI/OT, energía, manufactura, finanzas) para actualización de contenidos al menos cada 2 años.  Uso de resultados: actualización de programas, seriación y recursos didácticos; capacitación docente; adecuaciones a laboratorios y plataforma."}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"response_id": "lsadjf"}', NULL, NULL, '2026-01-09 21:48:48.404283+00', '2026-04-28 17:49:58.470598+00'),
	('ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', '089cdeda-d557-4a57-b49f-eb44921dfa3a', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería Mecatrónica (2026)', 'Semestre', 9, '{"nombre_autorizado_de_la_institucion": "Agregando nuevos datos con persistencia"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "notasAdicionales": "", "descripcionEnfoque": "Dame un plan de estudios realista y enfocado en física médica"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 202327, "total_tokens": 209102, "output_tokens": 6775, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5696}}, "responseId": "resp_08633e9c3f0021c000697299eb9c2881a2a3bdc31d43c4bf0d", "conversationId": null}}', NULL, NULL, '2026-01-22 21:44:28.093643+00', '2026-04-28 17:49:58.470598+00'),
	('49507442-ca7d-4489-b664-534321617950', '20593041-d605-4174-8404-4b152041eece', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Prueba', 'Cuatrimestre', 6, '{}', '40b640aa-3ec3-430c-9eb6-90f5ceffbbf7', true, 'MANUAL', '{}', NULL, NULL, '2026-02-03 21:57:35.015+00', '2026-04-28 17:49:58.470598+00'),
	('f6280a08-226d-480b-ab67-561e4657bfc4', 'b56eb209-245d-4258-a6a7-9dcb1d231cb4', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería Económica y Financiera', 'Semestre', 9, '{"nivel_y_nombre_del_plan_de_estudios": "x", "nombre_autorizado_de_la_institucion": "Unitec"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'MANUAL', '{}', NULL, NULL, '2026-01-30 14:33:50.818+00', '2026-04-28 17:49:58.470598+00'),
