	('0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', 'fafcf4b2-9d01-469b-bf91-2f338f29e5f5', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'w32423', 'ejemplo2', 'OPTATIVA', 2, 2, NULL, NULL, '{"ciclo": "Optativa", "clave_de_la_asignatura": "w32423", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante será capaz de aplicar el enfoque Six Sigma (principalmente DMAIC) para identificar, analizar y resolver problemas de calidad y procesos en organizaciones. Desarrollará competencias en recopilación y análisis de datos, uso de técnicas estadísticas y herramientas Lean, diseño de experimentos y elaboración de planes de control que permitan reducir la variabilidad y mejorar el desempeño de procesos, contribuyendo al perfil de egreso orientado a la mejora continua y la toma de decisiones basada en datos.", "modalidades_tecnologicas_e_informaticas": "La asignatura empleará plataformas de gestión del curso (LMS) para entrega de materiales y evaluaciones, software estadístico (por ejemplo Minitab, R o Python pandas/statsmodels), hojas de cálculo avanzadas (Excel con complementos estadísticos), herramientas de videoconferencia para sesiones sincrónicas y revisión de proyectos, y repositorios colaborativos (Git/GitHub o carpetas en la nube) para el trabajo en equipo. Se fomentará el uso de simuladores y plantillas para MSA, DOE y cartas de control.", "actividades_de_aprendizaje_independientes": "Estudio y lectura de materiales y artículos sobre Six Sigma y Lean; resolución de ejercicios estadísticos; preparación de reportes de avance del proyecto; análisis de datos reales o simulados; diseño y ejecución de experimentos en entornos controlados o simulados; elaboración de presentaciones y documentación de planes de control.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "ejemplo2", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y sesiones prácticas dirigidas para explicación de conceptos y herramientas; talleres guiados de análisis de datos y DOE; tutorías sobre selección y avance de proyectos; supervisión de pilotos y pruebas; retroalimentación estructurada a entregables y presentaciones; evaluación y defensa presencial o virtual de proyectos."}', '[{"temas": [{"nombre": "Origen, principios y objetivos de Six Sigma", "horasEstimadas": 8}, {"nombre": "Visión general de DMAIC y DMADV", "horasEstimadas": 8}, {"nombre": "Integración Lean-Six Sigma", "horasEstimadas": 6}, {"nombre": "Roles, estructura organizacional y despliegue (Champion, Black Belt, Green Belt)", "horasEstimadas": 6}, {"nombre": "Selección de proyectos y elaboración del project charter", "horasEstimadas": 12}], "titulo": "Introducción a Six Sigma y fundamentos del enfoque", "unidad": 1}, {"temas": [{"nombre": "Voz del cliente (VoC) y traducción a CTQ", "horasEstimadas": 12}, {"nombre": "Mapeo de procesos, SIPOC y diagramas de flujo", "horasEstimadas": 10}, {"nombre": "Planeación de recolección de datos y Análisis del sistema de medición (MSA)", "horasEstimadas": 16}, {"nombre": "Estadística descriptiva aplicada y índices de capacidad (Cp, Cpk)", "horasEstimadas": 12}, {"nombre": "Introducción a cartas de control y monitoreo de procesos", "horasEstimadas": 10}], "titulo": "Fase Definir y Medir: herramientas y recopilación de datos", "unidad": 2}, {"temas": [{"nombre": "Análisis de causa raíz: 5 Whys, diagrama de Ishikawa", "horasEstimadas": 12}, {"nombre": "Pruebas de hipótesis y su aplicación en mejora de procesos", "horasEstimadas": 12}, {"nombre": "Análisis de regresión y correlación para identificar relaciones críticas", "horasEstimadas": 12}, {"nombre": "ANOVA y análisis multivariado aplicado a problemas de calidad", "horasEstimadas": 12}, {"nombre": "Introducción práctica al diseño de experimentos (DOE)", "horasEstimadas": 12}], "titulo": "Fase Analizar: técnicas estadísticas y análisis de causas", "unidad": 3}, {"temas": [{"nombre": "Generación y priorización de ideas de mejora (KAIZEN, brainstorming, matriz Pugh)", 