	('1c375545-4de0-429b-90f4-963155593d8c', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LESE101', 'Fundamentos de inclusión y marco normativo', 'TRONCAL', 6, 1, '07a19d6f-a412-4993-b07d-4bc02b3d544a', NULL, '{"ciclo": "1er ciclo (Troncal)", "clave_de_la_asignatura": "LESE101", "criterios_de_evaluacion": "Trabajo final (análisis de caso y plan de inclusión): 30%; Ensayo/monografía sobre marco normativo: 20%; Portfolio de evidencias y adaptaciones prácticas: 20%; Participación en talleres y presentaciones grupales: 15%; Quizzes y evaluaciones parciales: 10%; Asistencia y participación en actividades dirigidas: 5%.", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante comprenderá los principios, políticas y marcos normativos nacionales e internacionales que sustentan la inclusión educativa; será capaz de identificar barreras a la participación y aprendizaje, aplicar criterios éticos y legales en la atención educativa, diseñar adaptaciones y planes de inclusión basados en buenas prácticas (incluyendo DUA y ajustes razonables) y evaluar la implementación de políticas y estrategias en contextos escolares.", "modalidades_tecnologicas_e_informaticas": "Uso de plataforma de gestión del aprendizaje (LMS) para distribución de materiales y evaluaciones; videoconferencias y grabaciones con subtitulado para sesiones síncronas; materiales en formatos accesibles (PDF etiquetado, HTML, audio); compatibilidad con lectores de pantalla; acceso a bases de datos legales y repositorios de recursos inclusivos; herramientas colaborativas (documentos compartidos, foros) y aplicaciones de apoyo (software de comunicación aumentativa, ampliadores de pantalla) para prácticas y evidencias.", "actividades_de_aprendizaje_independientes": "Lectura y análisis de textos legales y convenciones internacionales; elaboración de fichas de lectura y resúmenes críticos; preparación de un ensayo sobre un aspecto normativo; diseño y prueba de adaptaciones curriculares para una unidad didáctica; recopilación de evidencias para el portfolio; reflexión personal en bitácora sobre prácticas inclusivas; investigación y preparación de un breve informe sobre tecnologías de apoyo. (Estimadas 72 horas independientes).", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Fundamentos de inclusión y marco normativo", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y seminarios sobre marcos normativos y teorías de inclusión; análisis guiado de casos reales y jurisprudencia; talleres prácticos de diseño de adaptaciones y uso de tecnologías de apoyo; simulaciones y role-playing para atención inclusiva; sesiones de retroalimentación sobre trabajos y portfolios; presentaciones y defensa del plan de inclusión en ambiente supervisado."}', '[{"temas": [{"nombre": "Historia y conceptualización de la inclusión escolar", "horasEstimadas": 2}, {"nombre": "Principios y valores de la educación inclusiva", "horasEstimadas": 2}, {"nombre": "Barreras para la participación y aprendizaje", "horasEstimadas": 2}, {"nombre": "Modelos de discapacidad y sus implicaciones educativas", "horasEstimadas": 2}], "titulo": "Introducción a la inclusión educativa", "unidad": 1}, {"temas": [{"nombre": "Convenios y instrumentos internacionales (p. ej., CRPD)", "horasEstimadas": 2}, {"nombre": "Marco constitucional y legislación nacional sobre discapacidad", "horasEstimadas": 2}, {"nombre": "Derechos de niñas, niños y adolescentes con discapacidad en la escuela", "horasEstimadas": 2}, {"nombre": "Ética profesional y responsabilidad institucional", "horasEstimadas": 2}], "titulo": "Derechos humanos y discapacidad", "unidad": 2}, {"temas": [{"nombre": "Políticas educativas y normas sectoriales relacionadas con inclusión", "horasEstimadas": 3}, {"nombre": "Leyes y reglamentos específicos sobre educación inclusiva", "horasEstimadas": 3}, {"nombre": "Accesibilidad universal y ajustes razonables en el contexto escolar", "ho