	('48e962bd-4dd5-49f5-bc69-d8604d69384b', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LESE102', 'Desarrollo y diversidad neuropsicológica', 'TRONCAL', 6, 3, '32708950-6f54-48e2-b0e2-a205686a2ec7', NULL, '{"ciclo": "Segundo ciclo (TRONCAL)", "clave_de_la_asignatura": "LESE102", "criterios_de_evaluacion": "Exámenes parciales teóricos 25%; Proyecto integrador (evaluación e intervención de caso) 30%; Portafolio con informes neuropsicológicos y análisis de casos 20%; Talleres prácticos y demostraciones 15%; Participación y seminarios dirigidos 10%. Total 100%.", "fines_de_aprendizaje_o_formacion": "Proveer al estudiante de conocimientos y habilidades para comprender las bases neurobiológicas del desarrollo infantil, identificar perfiles neuropsicológicos asociados a discapacidades y trastornos del desarrollo, seleccionar y aplicar instrumentos de evaluación adecuados, y diseñar intervenciones y planes de inclusión basados en evidencia que integren perspectiva familiar e interdisciplinaria.", "modalidades_tecnologicas_e_informaticas": "Uso de plataforma educativa (LMS) para materiales, actividades y foros; videoconferencia para seminarios y supervisión; recursos multimedia (lecturas, cápsulas en video); software de presentación y procesamiento de datos (p. ej., hojas de cálculo, R/SPSS); acceso a baterías de evaluación neuropsicológica informatizadas y bancos de casos clínicos. Para modalidades mixtas o a distancia se garantizará acceso a bibliografía digital, herramientas de evaluación remota y entornos seguros para compartir informes.", "actividades_de_aprendizaje_independientes": "Lecturas críticas de artículos y capítulos; elaboración de informes neuropsicológicos a partir de casos; preparación del proyecto integrador (evaluación y plan de intervención); análisis estadístico básico de datos de evaluación; diarios de reflexión sobre práctica clínica y ética; estudio dirigido para exámenes parciales y preparación de seminarios.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Desarrollo y diversidad neuropsicológica", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y exposiciones guiadas; análisis y discusión de casos clínicos en grupo; demostraciones y práctica supervisada en la administración de pruebas neuropsicológicas; talleres de interpretación de resultados y elaboración de informes; sesiones de retroalimentación para el proyecto integrador; mesas interdisciplinarias con profesionales invitados."}', '[{"temas": [{"nombre": "Neuroanatomía y bases biológicas del desarrollo cerebral", "horasEstimadas": 6}, {"nombre": "Principios del desarrollo cognitivo, afectivo y social", "horasEstimadas": 4}, {"nombre": "Métodos y medidas en neuropsicología del desarrollo (neuroimagen, evaluaciones conductuales)", "horasEstimadas": 4}], "titulo": "Fundamentos del desarrollo neuropsicológico", "unidad": 1}, {"temas": [{"nombre": "Desarrollo prenatal y primera infancia: impacto en la trayectoria funcional", "horasEstimadas": 4}, {"nombre": "Desarrollo sensoriomotor y funciones ejecutivas emergentes", "horasEstimadas": 4}, {"nombre": "Desarrollo del lenguaje y comunicación: evaluación y indicadores tempranos", "horasEstimadas": 4}], "titulo": "Desarrollo típico: hitos y variabilidad", "unidad": 2}, {"temas": [{"nombre": "Trastorno del espectro autista: características cognitivas y socioemocionales", "horasEstimadas": 4}, {"nombre": "Trastorno por déficit de atención e hiperactividad (TDAH) y alteraciones ejecutivas", "horasEstimadas": 4}, {"nombre": "Discapacidad intelectual y desarrollo adaptativo", "horasEstimadas": 4}, {"nombre": "Trastornos específicos del aprendizaje y perfil neuropsicológico", "horasEstimadas": 4}], "titulo": "Perfiles neuropsicológicos en condiciones de diversidad del desarrollo", "unidad": 3}, {"temas": [{"nombre": "Baterías y pruebas neuropsicológicas: selección, aplicación e interpretación", "horasEstimadas": 3}, {"nombre": "Intervencio