	('1e83f4c0-c4ad-4e43-9971-ac373493154c', 'dc286072-c649-43aa-8a2f-aa3ef6166647', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'QFB304', 'Evaluación Sensorial y Psicofísica del Olfato', 'TRONCAL', 6, 6, '7946d5f9-3a99-4c46-b404-69b119650d34', NULL, '{"ciclo": "Segundo ciclo", "contenido_tematico": "1. Fundamentos de la evaluación sensorial y psicofísica del olfato\\n1.1 Principios de la percepción olfativa\\n1.2 Variables que afectan la apreciación olfativa\\n2. Métodos sensoriales, pruebas descriptivas y hedónicas\\n2.1 Métodos descriptivos: perfil sensorial, escalas de intensidad y escalas hedónicas\\n2.2 Pruebas hedónicas y aceptación de aromas\\n3. Selección y entrenamiento de paneles\\n3.1 Criterios de selección de panelistas\\n3.2 Protocolo de entrenamiento y calibración de descriptores\\n3.3 Control de consistencia y sesgos\\n4. Análisis y tratamiento de datos sensoriales\\n4.1 Diseño experimental y recolección de datos\\n4.2 Análisis estadístico básico (ANOVA, pruebas post hoc)\\n4.3 Modelos y técnicas para datos sensoriales (PCA, modelos lineales mixtos)\\n5. Aplicaciones, informes y ética\\n5.1 Elaboración de informes sensoriales\\n5.2 Consideraciones éticas, seguridad y bienestar de los panelistas", "clave_de_la_asignatura": "QFB304", "criterios_de_evaluacion": "Participación y asistencia en sesiones prácticas: 15%\\nCalibración y desempeño del panel: 25%\\nPruebas descriptivas: 25%\\nPruebas hedónicas: 15%\\nInforme de análisis de datos sensoriales: 20%", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el alumno será capaz de diseñar, ejecutar y analizar pruebas sensoriales olfativas utilizando métodos descriptivos y hedónicos; seleccionar y entrenar paneles de evaluación; aplicar análisis estadístico adecuado para interpretar resultados; elaborar informes técnicos con interpretación de hallazgos y consideraciones éticas y de seguridad en la evaluación sensorial.", "modalidades_tecnologicas_e_informaticas": "Laboratorio sensorial y plataformas digitales: software estadístico (R, Jamovi, Python) para análisis de datos sensoriales; gestión de paneles (base de datos de panelistas, calibración de descriptores); plataforma de gestión académica (LMS); herramientas de videoconferencia y comunicación; repositorio de recursos y datasets para prácticas", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas sobre fundamentos y métodos sensoriales olfativos\\nEjercicios de diseño de pruebas descriptivas y hedónicas\\nPrácticas de análisis de datos sensoriales con software estadístico\\nEjercicio de selección y calibración de paneles simulados\\nElaboración de un informe técnico preliminar de datos sensoriales", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Evaluación Sensorial y Psicofísica del Olfato", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Sesiones teóricas para introducir fundamentos y marco metodológico\\nPrácticas supervisadas de calibración y entrenamiento de paneles\\nRealización de pruebas descriptivas y hedónicas con panel de estudio\\nAnálisis guiado de datos sensoriales y discusión de resultados en clase\\nElaboración de informes técnicos en conjunto con retroalimentación del docente"}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1082, "total_tokens": 6798, "output_tokens": 5716, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 4928}}, "responseId": "resp_09287bea31abc243006993a0118d2881a3aadda6200e7fdf32", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Métodos sensoriales, selección y entrenamiento de paneles, pruebas descriptivas y hedónicas y análisis estadístico de datos sensoriales."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-16 22:54:08.826761+00', '2026-03-25 23:09:29.105343+00', 3, 8, 'borrador', '[]', NULL, '''1'':13B ''15'':153B,165B ''20'':172B ''25'':159B,162B ''academica'':262B ''academico'':343B ''aceptacion'