	('ec9fc465-92ef-4fd9-9d56-004169c9d2c9', 'dc286072-c649-43aa-8a2f-aa3ef6166647', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'QFB305', 'Tecnología de Cosméticos y Vehículos Fragranciados', 'OBLIGATORIA', 7, 2, '67cdbce0-04fe-4c19-aba9-c5999076c97c', NULL, '{"ciclo": "Ciclo 3", "contenido_tematico": "1. Fundamentos de emulsiones y sistemas vehiculares. 1.1 Tipos de emulsiones (O/W, W/O) y criterios de selección. 1.2 Fases internas y externas, tensioactivos y coemulgantes. 2. Excipientes y fragancias en cosméticos. 2.1 Funciones de excipientes (emolientes, humectantes, estabilizantes). 2.2 Compatibilidad entre fragancias y emulsiones. 3. Estabilidad y compatibilidad envase-producto. 3.1 Pruebas de estabilidad físico-química y métodos de evaluación. 3.2 Migración de fragancias y compatibilidad de envases (vidrio, PET, plásticos). 4. Diseño y control de formulaciones fragranciadas. 4.1 Métodos de formulación y escalado. 4.2 Control de calidad y fichas técnicas. 5. Regulación, seguridad y sostenibilidad. 5.1 Buenas prácticas de laboratorio y normativas. Distribución horaria: Horas académicas: 4; Horas independientes: 9.", "clave_de_la_asignatura": "QFB305", "criterios_de_evaluacion": "1) Proyecto de formulación de una emulsión cosmética fragranciada (40%). 2) Informe de pruebas de estabilidad y compatibilidad envase-producto (25%). 3) Examen teórico sobre fundamentos de emulsiones y fragancias (10%). 4) Diseño y evaluación de un caso de envase compatible (15%). 5) Participación y entrega de tareas y prácticas (10%).", "fines_de_aprendizaje_o_formacion": "Al concluir, el estudiante será capaz de: diseñar formulaciones básicas de emulsiones para cosméticos fragranciados; seleccionar excipientes y fragancias respetando seguridad y normativa; evaluar estabilidad físico-química y compatibilidad envase-producto; analizar migración y compatibilidad entre envase y producto; interpretar fichas técnicas y requerimientos regulatorios; comunicar resultados de formulación de manera clara y documentada.", "modalidades_tecnologicas_e_informaticas": "Laboratorio de formulación y pruebas; uso de software de formulación y registro de pruebas; bases de datos técnicas de excipientes y fragancias; plataformas LMS para seguimiento de actividades, videoconferencia y repositorio digital de fichas técnicas; recursos en línea de normas y buenas prácticas.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas de normativa y fichas técnicas; búsqueda de información sobre fragancias y compatibilidad con envases; desarrollo de la emulsión conceptual y revisión de datos; ejercicios de diseño y selección de envases; redacción del informe final y estudio de casos; preparación para el examen teórico.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Tecnología de Cosméticos y Vehículos Fragranciados", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases teóricas y prácticas guiadas por el docente; demostraciones de formulación de emulsiones; sesiones de laboratorio supervisadas para pruebas de estabilidad; revisión de fichas técnicas y discusión de resultados; análisis de casos de compatibilidad envase-producto; tutorías y asesoría para el proyecto final."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1081, "total_tokens": 6221, "output_tokens": 5140, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 4416}}, "responseId": "resp_0c79b29bdb930c9a006993a011c4948195a1cc5e70aa923f87", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Formulación de emulsiones y sistemas, excipientes, estabilidad y compatibilidad envase-producto en cosméticos fragranciados."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-16 22:54:08.826761+00', '2026-03-25 23:09:29.105343+00', 4, 9, 'borrador', '[]', NULL, '''1'':13B,134B ''1.1'':20B ''1.2'':30B ''10'':165B,185B ''15'':176B ''2'':38B,144B ''2.1'':44B ''2.2'':51B ''25'':155B 