,219B,226B,230B,235B,245B,254B,261B,271B,280B,291B,302B,310B,319B,326B,334B,354B,367B,390B,403B'),
	('f993d046-d822-4eb9-bfa6-5cbfc5a0ed7c', 'dc286072-c649-43aa-8a2f-aa3ef6166647', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'QFB306', 'Regulación y Evaluación de Seguridad para Fragancias', 'OBLIGATORIA', 5, 7, '67cdbce0-04fe-4c19-aba9-c5999076c97c', NULL, '{"ciclo": "Ciclo 4", "contenido_tematico": "1. Marco regulatorio y principios de seguridad de fragancias; 1.1 Definiciones, alcance y categorías de uso; 1.2 Marco regulatorio internacional y regional (IFRA) y nacional (COFEPRIS) y su interacción; 1.3 Principios de evaluación de seguridad y exposición; 2. Evaluación de seguridad y límites de uso; 2.1 Métodos para estimar exposición y límites de uso; 2.2 Dosis/MoS (Margin of Safety) y criterios de aprobación; 2.3 Estructura y contenido del dossier técnico; 3. Etiquetado y cumplimiento normativo; 3.1 Requisitos de etiquetado, fichas de datos de seguridad y advertencias; 3.2 Documentación y trazabilidad; 3.3 Procedimientos ante incumplimientos y vigilancia regulatoria; 4. Dossier técnico y dossier de seguridad; 4.1 Contenido, formato y periodicidad de actualizaciones; 4.2 Métodos analíticos y validación; 4.3 Gestión de cambios, revalidaciones y registro de versiones; 5. Procedimientos de cumplimiento; 5.1 Diseño de planes de cumplimiento en la organización; 5.2 Gestión de proveedores y sustancias reguladas; 5.3 Auditorías internas, externas y acciones correctivas; 6. Estudio de casos y aplicaciones prácticas; 6.1 Análisis de un caso IFRA; 6.2 Análisis de un caso COFEPRIS; 6.3 Elaboración de un mini-dossier para una fragancia propuesta.", "clave_de_la_asignatura": "QFB306", "criterios_de_evaluacion": "1) Examen teórico escrito 25%; 2) Dossier de cumplimiento de fragancias (ensayo técnico) 30%; 3) Participación y tareas en clase 15%; 4) Presentación de estudio de caso regulatorio 15%; 5) Proyecto de implementación de un plan de cumplimiento normativo en una empresa ficticia 15%.", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante habrá adquirido la capacidad de comprender y aplicar el marco regulatorio de fragancias (IFRA, COFEPRIS); analizar límites de uso y condiciones de seguridad; diseñar y gestionar un dossier técnico y la documentación de cumplimiento; interpretar requisitos de etiquetado y cumplir con las obligaciones regulatorias; proponer e implementar un plan de cumplimiento normativo en una empresa real o simulada.", "modalidades_tecnologicas_e_informaticas": "Modalidad: Presencial con apoyo de plataforma educativa; incluye acceso a bases de datos regulatorias (IFRA, COFEPRIS), repositorios de normas, software de gestión de cumplimiento, herramientas de búsqueda avanzada y foros de discusión; se requieren herramientas de colaboración en línea para actividades de equipo; para modalidades no escolares, se admite uso de plataformas sincrónicas y asincrónicas.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas de IFRA y COFEPRIS; revisión de fichas técnicas; búsqueda de límites de uso para sustancias aromáticas; análisis de casos de incumplimiento y elaboración de un mini-dossier; ejercicios de etiquetado y generación de un glosario de términos regulatorios; carga horaria estimada de 6 horas independientes.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Regulación y Evaluación de Seguridad para Fragancias", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "En las horas de clase (horas académicas: 2), se realizarán sesiones cortas magistrales, discusión guiada de casos, talleres de redacción de etiquetas y de contenido del dossier, revisión de marcos normativos aplicables y asesoría para el desarrollo del dossier, con retroalimentación del académico para guiar el aprendizaje y asegurar la cobertura de los objetivos de aprendizaje."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1082, "total_tokens": 7302, "output_tokens": 6220, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5312}}, "responseId": "resp_06d5e548c086b68b006993a01213348196995227e931772661", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Marco regulatorio (IFRA, COFEPRIS), etiquetado, límites de uso, dossier técnico y procedimientos de cumplimiento normativo."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-16 22:54:08.826761+00', '2026-03-25 23:09:29.105343+00', 2, 6, 'borrador', '[]', NULL, '''1'':14B,204B ''1.1'':23B ''1.2'':30B ''1.3'':43B ''15'':224B,232B,247B ''2'':51B,209B,458B ''2.1'':59B ''2.2'':68B ''2.3'':77B ''25'':208B ''3'':84B,218B ''3.1'':89B ''3.2'':100B ''3.3'':104B ''30'':217B ''4'':11B,111B,225B ''4.1'':118B ''4.2'':125B ''4.3'':130B ''5'':139B,233B ''5.1'':143B ''5.2'':152B ''5.3'':159B ''6'':166B,425B ''6.1'':173B ''6.2'':179B ''6.3'':185B ''a'':330B ''academicas'':457B ''academico'':450B,493B ''acceso'':329B ''acciones'':164B ''actividades'':361B,376B,443B ''actualizaciones'':124B ''admite'':369B ''adquirido'':260B ''advertencias'':99B ''al'':253B ''alcance'':25B ''analisis'':174B,180B,398B ''analiticos'':127B ''analizar'':274B ''ante'':106B ''aplicables'':482B ''aplicaciones'':171B ''aplicar'':266B ''apoyo'':324B ''aprendizaje'':250B,378B,435B,445B,497B,506B ''aprobacion'':76B ''aromaticas'':397B ''asegurar'':499B ''asesoria'':484B ''asignatura'':199B,256B,431B ''asincronicas'':375B ''auditorias'':160B ''avanzada'':348B ''bajo'':446B ''bases'':331B ''busqueda'':347B,390B ''cambios'':133B ''capacidad'':262B ''carga'':421B ''caso'':177B,183B,230B ''casos'':169B,400B,467B ''categorias'':27B ''ciclo'':9B,10B ''clase'':223B,455B ''clave'':196B ''cobertura'':501B ''cofepris'':39B,184B,273B,336B,385B ''colaboracion'':357B ''comprender'':264B ''con'':299B,323B,490B ''condiciones'':279B ''conduccion'':447B ''contenido'':12B,80B,119B,475B ''correctivas'':165B ''cortas'':462B ''criterios'':74B,201B ''cumplimiento'':87B,142B,148B,212B,241B,292B,309B,344B ''cumplir'':298B ''datos'':95B,333B ''de'':4A,19B,21B,28B,4