	('53f0ec58-566f-42eb-abdf-436bece1c19f', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIB307', 'Electrónica de Potencia para Control', 'OBLIGATORIA', 4, 1, '4bd2cc5c-6d06-44a6-b59f-0bd1d63dfbea', NULL, '{"ciclo": "7", "clave_de_la_asignatura": "CIB307", "criterios_de_evaluacion": "Exámenes parciales: 30%; Proyecto de diseño y prototipo: 30%; Prácticas de laboratorio y reportes: 15%; Tareas y ejercicios de simulación: 15%; Asistencia y participación en clase/laboratorio: 10%.", "fines_de_aprendizaje_o_formacion": "Que el estudiante comprenda y aplique los principios de conversión de potencia y el diseño de interfaces de potencia orientadas al control, sea capaz de seleccionar y modelar dispositivos semiconductores, dimensionar topologías de conversión (AC-DC, DC-DC, DC-AC), implementar estrategias de control para accionamientos y diseñar soluciones robustas con consideraciones térmicas, de protección y compatibilidad electromagnética, vinculando estos conocimientos al desarrollo de controladores y actuadores en aplicaciones industriales y de automatización.", "modalidades_tecnologicas_e_informaticas": "Uso de simuladores y herramientas de modelado (MATLAB/Simulink, PLECS, LTspice), software de diseño de PCB y magnetismo, instrumentación de laboratorio: osciloscopios de alta velocidad, analizadores de potencia y armónicos, fuentes de potencia con control, bancos de carga y equipos de seguridad eléctrica. Se emplearán repositorios en línea, aulas virtuales para entrega de actividades y herramientas de control embebido (microcontroladores/DSP) para integración con prototipos.", "actividades_de_aprendizaje_independientes": "Estudio dirigido de bibliografía especializada y normas; realización de simulaciones y modelos promedio; diseño y documentación del proyecto final; preparación de reportes de prácticas de laboratorio; resolución de problemas y ejercicios de cálculo; revisión de artículos y casos industriales relevantes.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Electrónica de Potencia para Control", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales para introducción de conceptos y desarrollo teórico; sesiones prácticas de laboratorio con prototipos y mediciones; demostraciones y montaje guiado de etapas de potencia; tutorías de proyecto y revisión de avances; seminarios sobre normativa, seguridad y casos de aplicación; evaluación teórica y práctica supervisada."}', '[{"temas": [{"nombre": "Dispositivos: diodos, tiristores, IGBT y MOSFET de potencia", "horasEstimadas": 3}, {"nombre": "Características estáticas y dinámicas; curvas corriente-tensión y pérdidas", "horasEstimadas": 3}, {"nombre": "Modelado, técnicas de conmutación y gestión térmica", "horasEstimadas": 2}], "titulo": "Fundamentos y dispositivos semiconductores de potencia", "unidad": 1}, {"temas": [{"nombre": "Rectificadores no controlados y controlados (monofásicos y trifásicos)", "horasEstimadas": 2}, {"nombre": "Técnicas de control de factor de potencia y rectificación activa", "horasEstimadas": 3}, {"nombre": "Filtros, armónicos y mitigación en etapas de entrada", "horasEstimadas": 3}, {"nombre": "Simulación y aplicación práctica de rectificadores", "horasEstimadas": 2}], "titulo": "Conversión AC-DC: rectificadores y control", "unidad": 2}, {"temas": [{"nombre": "Topologías básicas: buck, boost, buck-boost, sepic", "horasEstimadas": 3}, {"nombre": "Modos de conducción: continuo y discontinuo; análisis y diseño", "horasEstimadas": 2}, {"nombre": "Control PWM, modelado promedio y técnicas de regulación", "horasEstimadas": 3}, {"nombre": "Diseño de inductancias, transformadores y selección de componentes", "horasEstimadas": 2}], "titulo": "Conversión DC-DC: topologías y control", "unidad": 3}, {"temas": [{"nombre": "Topologías de inversores monofásicos y trifásicos", "horasEstimadas": 3}, {"nombre": "Técnicas de PWM analógicas y digitales (SPWM, SVPWM)", "horasEstimadas": 3}, {"nom