	('34c44d50-004e-4ee7-be20-de4db43874e5', 'dc286072-c649-43aa-8a2f-aa3ef6166647', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', '', 'Química OrgnánicaII', 'OBLIGATORIA', 4.3, NULL, NULL, NULL, '{"ciclo": "Ciclo II", "contenido_tematico": "1. Revisión de conceptos y fundamentos\n 1.1 Repaso de Química Orgánica I: estructuras, enlaces, isomería y conceptos de reactividad\n 1.2 Nomenclatura y evaluación de la reactividad\n\n2. Reacciones y mecanismos y estereoquímica\n 2.1 Mecanismos de reacción: sustitución, adición, eliminación y reorganización\n 2.2 Estereoquímica: quiralidad, isomería óptica y conformaciones\n\n3. Reacciones relevantes de carbonilos y derivados\n 3.1 Aldehídos y cetonas: nucleofilia, adición y condensaciones\n 3.2 Derivados de ácido carboxílico: ácidos, anhídridos, ésteres y amidas\n\n4. Reacciones de alcoholes, éteres y fenómenos de acilación\n 4.1 Reacciones de alcoholes: oxidación, deshidratación, esterificación\n 4.2 Reacciones de éteres y su utilidad sintética\n\n5. Síntesis orgánica avanzada y estrategias de planificación\n 5.1 Planificación de síntesis: retrosíntesis, selectividad y ruta eficiente\n 5.2 Uso de catalizadores y métodos modernos en síntesis\n\n6. Técnicas de caracterización y espectroscopía\n 6.1 Introducción a IR, NMR y MS para estructuras orgánicas\n 6.2 Interpretación de espectros y ejemplos prácticos", "clave_de_la_asignatura": "QO-II", "criterios_de_evaluacion": "- Tareas y prácticas de síntesis y problemas: 20%\n- Participación y asistencia: 10%\n- Exámenes parciales: 40%\n- Examen final: 30%", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante habrá desarrollado las capacidades para: 1) aplicar conceptos de química orgánica avanzada a problemas de síntesis y análisis; 2) diseñar rutas de síntesis selectivas y eficientes; 3) interpretar espectros (IR, NMR, MS) para confirmar estructuras; 4) explicar mecanismos de reacción y justificar elecciones de reacciones; 5) trabajar de forma colaborativa y comunicar resultados mediante informes y presentaciones.", "modalidades_tecnologicas_e_informaticas": "- Plataforma de gestión de aprendizaje (LMS) para contenidos y evaluaciones\n- Videoconferencia para clases en vivo\n- Simuladores y visualizadores de moléculas y mecanismos\n- Herramientas de procesamiento de datos espectroscópicos y elaboración de informes", "actividades_de_aprendizaje_independientes": "- Lecturas dirigidas y ejercicios de refuerzo\n- Resolución de problemas y ejercicios de síntesis\n- Preparación de informe de trabajo de laboratorio o simulación\n- Búsqueda y revisión de literatura breve", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Química Orgánica II", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "- Clases magistrales con explicación de mecanismos\n- Resolución de problemas en grupo y discusión de soluciones\n- Demostraciones de laboratorio y prácticas supervisadas\n- Tutorías y revisión de avances de proyectos de síntesis"}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1266, "total_tokens": 7346, "output_tokens": 6080, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5312}}, "responseId": "resp_0b1d903c1070e5ab006993a4902bf881a19b651f4638a84aeb", "conversationId": null}, "iaConfig": {"instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "La continuación de química orgánica"}, "referencias": {"archivosReferenciaIds": [], "repositoriosReferencia": []}, "generado_por": "ai_generate_subject"}', NULL, NULL, '2026-02-16 23:14:05.412008+00', '2026-03-25 23:09:29.105343+00', NULL, NULL, 'borrador', '[]', NULL, '''1'':8B,218B ''1.1'':15B ''1.2'':29B ''10'':193B ''2'':231B ''2.1'':44B ''2.2'':54B ''20'':188B ''3'':239B ''3.1'':70B ''3.2'':79B ''30'':201B ''4'':248B ''4.1'':100B ''4.2'':108B ''40'':197B ''5'':258B ''5.1'':126B ''5.2'':136B ''6.1'':153B ''6.2'':164B ''a'':155B,225B ''academico'':362B ''acido'':82B ''acidos'':84B ''acilaci