	('a1c71df9-3404-4d68-8b9e-5eeb6c605196', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CYB309', 'Control Predictivo y Optimización de Procesos', 'TRONCAL', 6, 1, 'ab51b6b5-6dd3-4651-8b76-cae879dbf577', NULL, '{"ciclo": "Cuarto ciclo", "clave_de_la_asignatura": "CYB309", "criterios_de_evaluacion": "Examen parcial (20%), Examen final (30%), Proyecto integrador (implementación y memoria) (25%), Laboratorios y prácticas (15%), Participación, tareas y actividades continuas (10%)", "fines_de_aprendizaje_o_formacion": "Formar en la capacidad de modelar procesos dinámicos, diseñar y evaluar controladores predictivos y aplicar técnicas de optimización para la regulación y eficiencia de procesos. El estudiante será capaz de seleccionar y validar modelos, formular y resolver problemas de MPC (incluyendo restricciones y consideraciones en tiempo real), y ejecutar implementaciones y pruebas en entornos de simulación y plataformas reales, contribuyendo al perfil de egreso con competencias en análisis, diseño y aplicación de estrategias avanzadas de control y optimización en sistemas industriales.", "modalidades_tecnologicas_e_informaticas": "Clases presenciales con apoyo de laboratorio computacional y simulación; uso de MATLAB/Simulink, Python (NumPy, SciPy, CasADi), solvers QP (OSQP, qpOASES), herramientas de identificación y control. Plataforma LMS para entrega de tareas y materiales, repositorios Git para control de código y colaboración. Para modalidades mixtas o no presencial se usarán videoconferencias, entornos virtuales de laboratorio y acceso remoto a simuladores.", "actividades_de_aprendizaje_independientes": "Lectura de capítulos y artículos, resolución de problemas y ejercicios de modelado, prácticas de identificación con datos reales, implementación de controladores MPC en Python/MATLAB, experimentación con solvers de optimización, desarrollo del proyecto integrador y elaboración de la memoria técnica.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Control Predictivo y Optimización de Procesos", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales con resolución guiada de problemas, demostraciones de simulaciones, sesiones de laboratorio dirigidas para implementación de MPC, tutorías para el proyecto integrador, análisis y discusión de casos industriales, evaluaciones parciales y retroalimentación continua."}', '[{"temas": [{"nombre": "Modelos de sistemas dinámicos: modelado físico, ecuaciones diferenciales, modelos de estado", "horasEstimadas": 4}, {"nombre": "Linealización, discretización y propiedades de sistemas (estabilidad, respuesta en frecuencia)", "horasEstimadas": 3}, {"nombre": "Conceptos básicos de control y formulación del problema de optimización en control", "horasEstimadas": 3}], "titulo": "Fundamentos de modelado y control", "unidad": 1}, {"temas": [{"nombre": "Técnicas de identificación paramétrica y no paramétrica (ARX, ARMAX, box-jenkins)", "horasEstimadas": 4}, {"nombre": "Modelos en espacio de estados y reducción de orden para control", "horasEstimadas": 3}, {"nombre": "Estimación de parámetros y validación de modelos para uso en MPC", "horasEstimadas": 3}], "titulo": "Identificación y modelado para control predictivo", "unidad": 2}, {"temas": [{"nombre": "Formulación del problema de MPC: horizonte de predicción y control, función de coste", "horasEstimadas": 4}, {"nombre": "Incorporación de restricciones en entradas y salidas", "horasEstimadas": 3}, {"nombre": "Pesos Q y R, seguimiento de referencia y rechazo de perturbaciones", "horasEstimadas": 3}, {"nombre": "Estrategia receding horizon y actualización en tiempo discreto", "horasEstimadas": 2}], "titulo": "Diseño de Control Predictivo Modelo (MPC) básico", "unidad": 3}, {"temas": [{"nombre": "Programación cuadrática (QP) y lineal (LP) como problemas de MPC", "horasEstimadas": 4}, {"nombre": "Algoritmos numéricos y solvers para tiempo real (active-set, interior-point, OSQP)", 