	('eb8fb1d0-15eb-4978-ab65-8d863633cbfc', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CYB308', 'Pruebas de Intrusión en Entornos Industriales', 'OPTATIVA', 3, 7, 'e8de5e3f-3ac1-45bf-a1fb-454cca534f71', NULL, '{"ciclo": "Optativa", "clave_de_la_asignatura": "CYB308", "criterios_de_evaluacion": "Laboratorios prácticos y entregables de laboratorio: 30%; Ejercicio práctico de pentesting en laboratorio (evaluación de explotación y mitigación): 30%; Informe técnico profesional (report): 20%; Participación en clase, debates y actividades dirigidas: 10%; Examen teórico-práctico final: 10%. Total: 100%.", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante será capaz de aplicar metodologías de pruebas de intrusión y evaluación de vulnerabilidades específicas para redes y dispositivos de control industrial (ICS/SCADA), diseñar y ejecutar pruebas en entornos controlados reduciendo riesgos operativos, priorizar hallazgos según impacto en la continuidad operacional y elaborar reportes técnicos y ejecutivos con recomendaciones de mitigación y remediación que permitan mejorar la ciberseguridad de sistemas OT.", "modalidades_tecnologicas_e_informaticas": "Se emplearán laboratorios virtuales y físicos replicados para entornos OT (OpenPLC, MiniCPS, simuladores de HMI/PLC), herramientas de análisis de red (Wireshark), frameworks de pentesting (Metasploit, Scapy), scanners y herramientas OT específicas; plataformas de gestión de laboratorios remotos y control de versiones para entregables; comunicación y seguimiento mediante LMS, correo institucional y foros. Se requiere acceso a máquina virtual con Linux y permisos adecuados para prácticas en entornos controlados.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas sobre protocolos industriales y vulnerabilidades (aprox. 10 h), preparación y práctica en laboratorio virtual (aprox. 12 h), elaboración de reportes y análisis de casos (aprox. 6 h), investigación de vulnerabilidades y actualización de herramientas (horas distribuidas). Total estimado de horas independientes: 30.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Pruebas de Intrusión en Entornos Industriales", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y exposiciones (conceptos y protocolos), demostraciones de herramientas en vivo, laboratorios guiados paso a paso en entornos replicados, estudios de caso y análisis de incidentes reales, sesiones de retroalimentación sobre informes y ejercicios prácticos, evaluaciones prácticas supervisadas."}', '[{"temas": [{"nombre": "Características de sistemas OT y diferencias con IT", "horasEstimadas": 2}, {"nombre": "Arquitectura ICS/SCADA y elementos críticos", "horasEstimadas": 2}, {"nombre": "Riesgos, amenazas y casos reales en entornos industriales", "horasEstimadas": 2}], "titulo": "Introducción a la seguridad en entornos industriales", "unidad": 1}, {"temas": [{"nombre": "Fundamentos de protocolos industriales: Modbus, DNP3, OPC, IEC 61850", "horasEstimadas": 3}, {"nombre": "Captura y análisis de tráfico OT (Wireshark, decodificadores y técnicas de inspección)", "horasEstimadas": 3}, {"nombre": "Segmentación de red, zonas y arquitecturas de defensa para OT", "horasEstimadas": 2}], "titulo": "Protocolos industriales y análisis de redes", "unidad": 2}, {"temas": [{"nombre": "Escaneo de activos y fingerprinting específico para dispositivos industriales", "horasEstimadas": 2}, {"nombre": "Evaluación de vulnerabilidades en PLC, RTU y HMI", "horasEstimadas": 2}, {"nombre": "Priorización de hallazgos y gestión de riesgos en entornos industriales", "horasEstimadas": 2}], "titulo": "Descubrimiento y evaluación de vulnerabilidades en OT", "unidad": 3}, {"temas": [{"nombre": "Técnicas de explotación en entornos controlados (explotaciones no destructivas)", "horasEstimadas": 3}, {"nombre": "Controles de seguridad y mitigaciones (IDS/IPS OT, listados blancos, segmentación)", "hor