	('4b24eecf-6d23-4f88-b382-97259fa58c88', '3ebc1d1c-e950-4a6e-948f-bb89efa40e77', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MKT-ML301', 'Aprendizaje automático para investigación de mercados', 'TRONCAL', 6, 4, '660da7cc-c4c9-43e9-8aa2-ad9b6504a316', NULL, '{"ciclo": "Ciclo II", "contenido": null, "clave_de_la_asignatura": "MKT-ML301", "criterios_de_evaluacion": "Examen parcial teórico-práctico (20%): evaluación de conceptos y habilidades básicas. Talleres y ejercicios prácticos en sesión (25%): resolución de problemas en entornos de laboratorio. Proyecto de investigación de mercados con ML (35%): análisis end-to-end desde selección de datos hasta interpretación de resultados y consideraciones de ética. Participación y asistencia (10%): participación activa, uso de notebooks y discusiones. Presentación y defensa del proyecto (10%): exposición de hallazgos y justificación de decisiones metodológicas.", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante será capaz de: comprender fundamentos de machine learning aplicados a investigación de mercados; aplicar técnicas de regresión, clasificación y clustering a datasets de mercados; validar, comparar e interpretar modelos; diseñar y describir pipelines de modelado y consideraciones de despliegue; identificar sesgos, aspectos éticos y de privacidad; comunicar resultados de forma clara para apoyar la toma de decisiones en investigación de mercados.", "modalidades_tecnologicas_e_informaticas": "Recursos tecnológicos y de información: Python (pandas, numpy, scikit-learn), Jupyter Notebooks o Google Colab, herramientas de visualización (matplotlib/seaborn), control de versiones con Git y repositorios en GitHub. Plataformas de cómputo en la nube o en entornos institucionales (Colab, JupyterHub, AWS/GCP/Azure) para prácticas y experimentos. En modalidades no escolarizada o mixta, es obligatorio contar con entornos de cómputo accesibles para realizar las prácticas.", "actividades_de_aprendizaje_independientes": "Proyecto independiente de análisis de un conjunto de datos de investigación de mercados: definición del objetivo, limpieza y preprocesamiento de datos, selección y entrenamiento de modelos, evaluación y reporte de resultados, con énfasis en interpretación y consideraciones éticas (6 horas). Lecturas dirigidas y ejercicios de refuerzo (2 horas).", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Aprendizaje automático para investigación de mercados", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y demostraciones dirigidas por el académico (4 horas): conceptos teóricos y casos de uso en investigación de mercados. Laboratorios guiados (4 horas): implementación de modelos, ejecución de pipelines y validación de resultados, con supervisión del docente. Discusión de consideraciones éticas y de privacidad en contextos reales."}', '[{"temas": [], "titulo": "Nueva Unidad", "unidad": 1}]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1094, "total_tokens": 7402, "output_tokens": 6308, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5696}}, "responseId": "resp_04a9bec1e4a2db3800699cbee23f60819ea6c5b8af3d30e5e4", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Fundamentos y aplicaciones de machine learning en investigación de mercados: regresión, clasificación, clustering, validación, despliegue y consideraciones éticas y de privacidad."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-23 20:56:00.968045+00', '2026-03-25 23:09:29.105343+00', 4, 8, 'borrador', '[]', NULL, '''1'':368B ''10'':79B,92B ''2'':291B ''20'':30B ''25'':43B ''35'':58B ''4'':323B,337B ''6'':283B ''a'':121B,132B ''academico'':314B,322B ''accesibles'':236B ''activa'':81B ''actividades'':241B,307B ''al'':106B ''analisis'':59B,248B ''aplicados'':120B ''aplicar'':125B ''apoyar'':164B ''aprendizaje'':1A,103B,243B,300B,301B,309B ''asignatur