	('4e27c298-70c2-4550-9103-649f127a026e', 'dc286072-c649-43aa-8a2f-aa3ef6166647', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'QFB311', 'Metrología y validación analítica para aromaquímicos', 'OBLIGATORIA', 4, NULL, NULL, NULL, '{"ciclo": "7", "clave_de_la_asignatura": "QFB311", "criterios_de_evaluacion": "Examen parcial teórico 20%; Examen final teórico-práctico 25%; Informes de prácticas de laboratorio (entregables) 20%; Proyecto integrador (protocolo y reporte de validación para liberación de lote) 25%; Participación y desempeño en prácticas 10%.", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura el estudiante será capaz de asegurar la trazabilidad metrológica en análisis de aromaquímicos, calibrar y verificar equipos analíticos, diseñar y ejecutar planes de validación de métodos, evaluar y cuantificar la incertidumbre de medición, implementar controles de calidad y elaborar informes técnicos conformes para la liberación de lotes, contribuyendo al cumplimiento de normas regulatorias y a la garantía de calidad en la industria de aromas.", "modalidades_tecnologicas_e_informaticas": "Clases presenciales con uso de equipos analíticos (GC, GC-MS, HPLC), balanzas y volumetría; software de control de instrumentos y adquisición de datos; herramientas de análisis estadístico (Excel avanzado, R o similar); paquetes para cálculo de incertidumbre; sistemas LIMS y plantillas electrónicas para informes; plataforma educativa (Moodle o equivalente) para materiales, foros y entregas. Para modalidad mixta o no escolarizada se incluirán simuladores de laboratorio y videodemostraciones.", "actividades_de_aprendizaje_independientes": "Revisión bibliográfica y normativa sobre trazabilidad y validación; preparación y cálculo de patrones y soluciones estándar; análisis de datos de calibración y validación; cálculo de incertidumbre y generación de gráficos de control; redacción de informes técnicos y protocolos; estudio de casos y simulaciones mediante software estadístico.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Metrología y validación analítica para aromaquímicos", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y seminarios para teoría y normativa; demostraciones instrumentales y sesiones guiadas de calibración; prácticas de laboratorio supervisadas para ejecución de validaciones y determinación de incertidumbre; discusión de casos reales y resolución de problemas en equipo; retroalimentación individualizada sobre informes y presentaciones."}', '[{"temas": [{"nombre": "Principios de metrología y trazabilidad en el laboratorio analítico", "horasEstimadas": 3}, {"nombre": "Sistemas de unidades, patrones y certificados de referencia", "horasEstimadas": 3}, {"nombre": "Estadística básica aplicada a mediciones y control de datos", "horasEstimadas": 2}], "titulo": "Fundamentos de metrología y trazabilidad aplicados a aromaquímicos", "unidad": 1}, {"temas": [{"nombre": "Calibración y verificación de cromatógrafos (GC, GC-MS, HPLC) y detectores", "horasEstimadas": 4}, {"nombre": "Preparación y manejo de patrones primarios y secundarios para aromaquímicos", "horasEstimadas": 3}, {"nombre": "Construcción de curvas de calibración y evaluación de ajuste", "horasEstimadas": 3}], "titulo": "Calibración de equipos e instrumentos para aromaquímicos", "unidad": 2}, {"temas": [{"nombre": "Parámetros de validación: exactitud, precisión, linealidad y selectividad", "horasEstimadas": 5}, {"nombre": "Determinación de LOD, LOQ, robustez y rangos de trabajo", "horasEstimadas": 4}, {"nombre": "Validación específica por matriz: aceites esenciales, materias primas y formulaciones", "horasEstimadas": 3}], "titulo": "Validación de métodos analíticos para aromaquímicos", "unidad": 3}, {"temas": [{"nombre": "Identificación de las fuentes de incertidumbre en análisis de aromaquímicos", "horasEstimadas": 3}, {"nombre": "Cálculo de incertidumbre tipo A y tipo B", "horasEstimadas": 3}, {"nombre": "Propagación, combin