	('b60bdb03-72d2-4ff7-9046-e4d1315077bb', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LESE109', 'Práctica supervisada I: acompañamiento en aula', 'TRONCAL', 6, NULL, NULL, NULL, '{"ciclo": "Séptimo ciclo (TRONCAL)", "clave_de_la_asignatura": "LESE109", "criterios_de_evaluacion": "1) Registros y fichas de observación (25%); 2) Evaluación del supervisor institucional (20%); 3) Portafolio de evidencias incluyendo registros y producciones (20%); 4) Informe reflexivo final y propuesta de mejora (20%); 5) Asistencia, cumplimiento de acuerdos y participación en sesiones de retroalimentación (15%).", "fines_de_aprendizaje_o_formacion": "Que el estudiante desarrolle competencias para acompañar prácticas docentes en aula mediante observación sistemática, registro riguroso de evidencias y diseño básico de micro-intervenciones, manteniendo postura ética y profesional; al concluir, el estudiante será capaz de documentar situaciones pedagógicas reales, analizar prácticas docentes con base en evidencias y formular propuestas de mejora coherentes con las necesidades observadas, contribuyendo al logro del perfil de egreso en formación docente.", "modalidades_tecnologicas_e_informaticas": "Uso de plataforma educativa (LMS) para entrega de evidencias y comunicación con el docente supervisor; aplicaciones móviles o tabletas para registro de observación (formularios, grabación de audio/video con consentimiento), hojas de cálculo para sistematización de datos, herramientas de edición de documentos y presentaciones, videoconferencia para sesiones de retroalimentación remotas y repositorio digital para el portafolio.", "actividades_de_aprendizaje_independientes": "Lectura de material teórico sobre observación y acompañamiento; análisis de videos de clases y práctica de registro; preparación de instrumentos y guías de observación; elaboración y revisión del portafolio; redacción del informe reflexivo; estudio de casos y planificación de micro-intervenciones; coordinación previa con docente tutor.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Práctica supervisada I: acompañamiento en aula", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Orientación inicial sobre protocolos y ética; demostración y práctica guiada de uso de instrumentos de observación; acompañamiento en salida a aula y supervisión en tiempo real de sesiones de sombra; sesiones de retroalimentación colectiva e individual con el supervisor; seguimiento y validación de micro-intervenciones; revisión y asesoría para la construcción del portafolio y el informe final."}', '[{"temas": [{"nombre": "Marco conceptual, ético y normativo del acompañamiento en aula", "horasEstimadas": 4}, {"nombre": "Instrumentos y protocolos de observación (fichas, listas de cotejo, rúbricas)", "horasEstimadas": 4}, {"nombre": "Planificación de sesiones de observación y acuerdos con el docente tutor", "horasEstimadas": 4}], "titulo": "Preparación para la práctica de acompañamiento", "unidad": 1}, {"temas": [{"nombre": "Observación libre y toma de registros descriptivos", "horasEstimadas": 8}, {"nombre": "Observación estructurada con listas de cotejo y registros cuantitativos", "horasEstimadas": 8}, {"nombre": "Análisis inicial de prácticas docentes a partir de evidencias", "horasEstimadas": 6}, {"nombre": "Relación, comunicación y postura profesional durante la sombra", "horasEstimadas": 6}], "titulo": "Observación dirigida en contextos reales (sombra)", "unidad": 2}, {"temas": [{"nombre": "Registro sistemático, categorización de evidencias y construcción de casos", "horasEstimadas": 8}, {"nombre": "Diseño de micro-intervenciones de apoyo: objetivos, estrategias y materiales", "horasEstimadas": 8}, {"nombre": "Ejecución supervisada de micro-intervenciones en aula", "horasEstimadas": 6}, {"nombre": "Adaptaciones didácticas y atención a la diversidad en la intervención", "horasEstimadas": 6}], "titulo": "Registros orientados a la intervención y micro-i