	('cbc9bb28-cd0c-41e1-be92-4fc71fe31ea3', '26806567-c5ee-404e-8f90-0f0711c21ea0', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MET-1', 'Metodología del Estudio del Derecho', 'OBLIGATORIA', 1, NULL, NULL, NULL, '{"ciclo": "Por definir", "contenido_tematico": "1. Enfoque y fundamentos de la metodología del derecho\\n  1.1. Lectura jurídica y análisis de textos legales\\n  1.2. Interpretación de leyes y normas\\n  1.3. Introducción al método de casos y razonamiento jurídico\\n  1.4. Uso de herramientas digitales para el estudio jurídico\\n  1.5. Ética y buenas prácticas en el estudio del derecho", "clave_de_la_asignatura": "MET-1", "criterios_de_evaluacion": "1. Lecturas y análisis de textos jurídicos: 30%\\n  2. Análisis de casos y ejercicios prácticos: 40%\\n  3. Participación y asistencia: 20%\\n  4. Trabajo final/portafolio que integre el uso de herramientas digitales: 10%", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante será capaz de:\\n  - Realizar lectura y análisis crítico de textos jurídicos y normas.\\n  - Aplicar el método de casos para el razonamiento y la solución de problemas jurídicos.\\n  - Emplear herramientas digitales y recursos en línea para la organización, búsqueda y citación de información jurídica.\\n  - Explicar de manera clara y coherente sus razonamientos jurídicos.", "modalidades_tecnologicas_e_informaticas": "Se emplearán recursos tecnológicos y de información para el desarrollo del proceso de enseñanza-aprendizaje: \\n  - Plataforma de gestión académica (LMS) para materiales, foros y entrega de trabajos.\\n  - Herramientas de lectura y anotación de PDFs.\\n  - Bases de datos jurídicas y buscadores en línea (p. ej., legislación, jurisprudencia, doctrina).\\n  - Herramientas de citación bibliográfica (Zotero, Mendeley) y procesamiento de textos.\\n  - Presentaciones y videoconferencias (Zoom, Teams) para sesiones sincrónicas o híbridas.\\n  - Entornos de colaboración para debates y trabajos en grupo.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas de textos legales y doctrinales; realización de resúmenes; análisis de casos breves; ejercicios de interpretación de normas; investigación de fuentes jurisprudenciales; elaboración de cuestionarios y respuestas; desarrollo de un portafolio digital con evidencias de manejo de herramientas digitales y metodológicas.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Metodología del Estudio del Derecho", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Actividades en clase dirigidas por el académico:\\n  - Discusión y análisis guiados de textos jurídicos.\\n  - Resolución de casos breves en grupo, con retroalimentación.\\n  - Talleres sobre técnicas de lectura jurídica y extracción de elementos clave.\\n  - Demostraciones de uso de herramientas digitales para búsqueda, citación y organización de información.\\n  - Revisión de avances de trabajos y orientación metodológica."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1097, "total_tokens": 5940, "output_tokens": 4843, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 4096}}, "responseId": "resp_01ed90476500a652006989ff839e58819d8753781481a87699", "conversationId": null}, "iaConfig": {"instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Análisis jurídico así como análisis de textos legales, introducción al método de casos y uso de herramientas digitales para el estudio jurídico."}, "referencias": {"archivosReferenciaIds": [], "repositoriosReferencia": []}, "generado_por": "ai_generate_subject"}', NULL, NULL, '2026-02-09 15:39:19.551496+00', '2026-03-25 23:09:29.105343+00', NULL, NULL, 'borrador', '[]', NULL, '''-1'':7A,74B ''1'':13B,78B ''1.1'':23B ''1.2'':32B ''1.3'':39B ''1.4'':49B ''1.5'':59B ''10'':112B ''2'':87B ''20'':100B ''3'':96B ''30'':85B ''4'':102B ''40'':94B ''academica'':204B ''academico'':333B,340B ''actividades'':267B,326B,334B ''al'':4