	('4f296f95-bc10-47cb-b16f-0c82559d1906', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIB304', 'Sistemas de Control Distribuido y SCADA', 'OBLIGATORIA', 5, 1, '90d396e2-9ad7-46b3-9a04-43b6a3b57812', NULL, '{"ciclo": "7", "clave_de_la_asignatura": "CIB304", "criterios_de_evaluacion": "Examen parcial 25% / Examen final 30% / Proyecto integrador (diseño y configuración DCS/SCADA) 25% / Prácticas de laboratorio y reportes 10% / Participación y actividades en clase 10%", "fines_de_aprendizaje_o_formacion": "Formar al estudiante para comprender y aplicar arquitecturas DCS y SCADA en entornos industriales, diseñar sistemas de supervisión y control distribuidos, seleccionar protocolos y dispositivos de campo, asegurar comunicaciones robustas y aplicar prácticas de ciberseguridad y puesta en marcha, contribuyendo al perfil de egreso con competencias para integrar y operar sistemas de control industrial.", "modalidades_tecnologicas_e_informaticas": "Uso de software SCADA/HMI (p. ej. Ignition, Wonderware, Siemens WinCC), simuladores de DCS/PLC, plataformas virtuales (VM) con servidores OPC UA/OPC DA, bancos de pruebas con PLCs y módulos I/O, analizadores de red industrial y herramientas para configuración de VLAN/QoS; se empleará un LMS para contenidos, foros y entrega de prácticas.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas y estudio de manuales de protocolos y normas; resolución de ejercicios de configuración y diagnóstico; desarrollo de simulaciones y modelado en herramientas SCADA/DCS; preparación del proyecto integrador y reportes de laboratorio; revisión de casos de estudio y preparación de exámenes.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Sistemas de Control Distribuido y SCADA", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales con análisis de arquitectura y protocolos; sesiones prácticas guiadas en laboratorio y simuladores; talleres de diseño de HMI y gestión de alarmas; prácticas de configuración de redes industriales y pruebas de integración DCS–SCADA; sesiones de revisión y retroalimentación del proyecto integrador."}', '[{"temas": [{"nombre": "Conceptos fundamentales y diferencias entre DCS y SCADA", "horasEstimadas": 2}, {"nombre": "Arquitectura general y componentes: controladores, I/O, HMI y servidores", "horasEstimadas": 2}, {"nombre": "Modelos de implementación y ejemplos en la industria", "horasEstimadas": 2}], "titulo": "Introducción a DCS y SCADA", "unidad": 1}, {"temas": [{"nombre": "Sensores y actuadores: selección, características e interfaces", "horasEstimadas": 3}, {"nombre": "Módulos de entradas/salidas y arquitecturas I/O remotas", "horasEstimadas": 3}, {"nombre": "Protocolos de campo: HART, FOUNDATION Fieldbus, Profibus, Modbus", "horasEstimadas": 4}], "titulo": "Dispositivos de campo e interfaces", "unidad": 2}, {"temas": [{"nombre": "Topologías de red industrial y Ethernet industrial", "horasEstimadas": 3}, {"nombre": "Protocolos de comunicación: TCP/IP industrial, OPC UA, MQTT", "horasEstimadas": 3}, {"nombre": "Diseño de redes deterministas: switches gestionados, VLANs, QoS y tiempo real", "horasEstimadas": 4}], "titulo": "Redes y protocolos de comunicación en entornos industriales", "unidad": 3}, {"temas": [{"nombre": "Controladores distribuidos: estructura, bloques de función y escalabilidad", "horasEstimadas": 3}, {"nombre": "Estrategias de control: PID, secuencias y control avanzado", "horasEstimadas": 3}, {"nombre": "Redundancia, alta disponibilidad y gestión de fallos", "horasEstimadas": 2}], "titulo": "Diseño y operación de sistemas DCS", "unidad": 4}, {"temas": [{"nombre": "Diseño de HMI y principios de usabilidad para operación segura", "horasEstimadas": 3}, {"nombre": "Gestión de alarmas, tendencias y sistemas historian", "horasEstimadas": 3}, {"nombre": "Reportes, análisis de datos y acceso remoto/telemetría", "horasEstimadas": 2}], "titulo": "Supervisión SCADA e interfaces HMI", "u