	('3408baf0-c967-41e2-b63a-20664d7fea9e', '79fba458-aea4-4ca8-ab76-943ede479f15', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'PRI101', 'Fundamentos de Investigación', 'TRONCAL', 4, 1, '1f875112-f9de-451c-acf1-a34601bba1a3', NULL, '{"ciclo": "Ciclo formativo troncal", "contenido_tematico": "1. Fundamentos de la investigación científica y del método científico; 1.1 Paradigmas y epistemologías; 1.2 Formulación de preguntas de investigación y objetivos. 2. Diseño de investigación; 2.1 Tipos de investigación (exploratoria, descriptiva, explicativa, experimental); 2.2 Diseño de estudios cualitativos y cuantitativos; 2.3 Muestreo, validez y confiabilidad. 3. Redacción y comunicación científica; 3.1 Estructura de reportes y artículos; 3.2 Normas de citación y gestión de referencias (APA); 3.3 Presentación de resultados (tablas, figuras, gráficos). 4. Ética, reproducibilidad y calidad de la evidencia; 4.1 Ética en la investigación; 4.2 Revisión por pares y plagio. 5. Proyecto integrador; 5.1 Planteamiento del problema y diseño de protocolo; 5.2 Elaboración de propuesta de investigación. Carga horaria total: 48 horas académicas presenciales y 80 horas de trabajo independiente. Créditos: 4.", "clave_de_la_asignatura": "PRI101", "criterios_de_evaluacion": "1) Participación y asistencia en clase (10%); 2) Diseño de estudio y entrega de plan de investigación (35%); 3) Informe de proyecto o artículo corto (25%); 4) Examen teórico (20%); 5) Presentación oral de resultados/defensa de la propuesta (10%).", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante será capaz de: a) formular preguntas y objetivos de investigación; b) diseñar un protocolo de estudio (tipos de diseño, muestreo y técnicas de recolección de datos); c) realizar búsquedas bibliográficas y gestionar referencias; d) redactar propuestas de investigación y reportes académicos con estructura y normas de citación; e) interpretar resultados y comunicar hallazgos de forma ética.", "modalidades_tecnologicas_e_informaticas": "Plataforma de gestión del aprendizaje (LMS) y herramientas de videoconferencia; procesadores de texto y herramientas de revisión de estilo; gestión de referencias (Zotero o Mendeley); software de análisis básico (R o SPSS); herramientas de nube para almacenamiento y colaboración; requisitos de comunicación asincrónica (foros, correo) y sincrónica (tutorías, sesiones). Nota: para las modalidades no escolarizada y mixta, este elemento es obligatorio.", "actividades_de_aprendizaje_independientes": "Lectura y análisis crítico de literatura relevante; búsquedas bibliográficas y evaluación de fuentes; redacción de borradores de cada sección de la propuesta; elaboración de un esquema y un protocolo de investigación; desarrollo de resúmenes y fichas de lectura; ejercicios de citación y parafraseo; revisión de pares entre estudiantes.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Fundamentos de Investigación", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Sesiones magistrales y talleres de diseño de investigación; revisión guiada de borradores de propuesta; tutorías individuales para apoyo en planteamiento del problema, diseño y metodología; talleres de redacción y normas de citación; defensa de la propuesta ante el grupo y/o panel docente; sesiones de retroalimentación sobre avances del proyecto y su implementación."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1066, "total_tokens": 6995, "output_tokens": 5929, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5120}}, "responseId": "resp_0dbb980a81988a2d00698f49ba77ac819fb5f109ec2cd8b08d", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Introducción a métodos científicos, diseño de investigación y redacción académica para proyectos de grado y trabajos científicos."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-13 15:56:39.845265+00', '2