	('0e527a2b-b7c5-43c8-8ca1-76014a26f877', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIB-ARC105', 'Arquitectura de Software para Sistemas de Control', 'OBLIGATORIA', 4, 5, 'cabe3be1-346a-4660-b15e-6b6051c4e2b6', NULL, '{"ciclo": "Quinto ciclo", "clave_de_la_asignatura": "CIB-ARC105", "criterios_de_evaluacion": "Laboratorios prácticos y ejercicios de integración (25%), Proyecto integrador de arquitectura para un sistema de control (40%), Examen parcial sobre conceptos y patrones (20%), Presentación y defensa del proyecto (10%), Participación y asistencia en actividades dirigidas (5%)", "fines_de_aprendizaje_o_formacion": "Que el estudiante diseñe y evalúe arquitecturas de software robustas para sistemas de supervisión y control industrial, aplicando patrones de diseño, principios de modularidad y buenas prácticas de pruebas y CI/CD, considerando requisitos de confiabilidad, seguridad y mantenibilidad propios del dominio industrial.", "modalidades_tecnologicas_e_informaticas": "Uso de herramientas y entornos como repositorios Git, plataformas de CI/CD (por ejemplo Jenkins, GitLab CI), contenedores Docker, simuladores/entornos de PLC y SCADA para prácticas, entornos de pruebas automatizadas (unitarias, integración), y herramientas de modelado (UML, diagramas de arquitectura). Se emplearán recursos digitales para entrega y evaluación (repositorios remotos, pipelines en la nube) y material multimedia para apoyo docente.", "actividades_de_aprendizaje_independientes": "Estudio y lectura crítica de patrones y casos de estudio; desarrollo de módulos de software y pruebas unitarias; implementación y configuración de pipelines CI/CD para proyectos prácticos; preparación de entregables del proyecto integrador; revisión de documentación técnica y normas de seguridad aplicables al contexto industrial.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Arquitectura de Software para Sistemas de Control", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales sobre patrones y principios arquitectónicos; sesiones prácticas guiadas de diseño modular y de integración con simuladores industriales; talleres para configurar pipelines CI/CD y ejecutar pruebas automatizadas; revisión y retroalimentación de avances del proyecto integrador; exposiciones y defensa de soluciones arquitectónicas."}', '[{"temas": [{"nombre": "Patrones de diseño y arquitectura aplicados a sistemas de control (p. ej. MVC, Broker, Pipe-and-Filter, Event-Driven)", "horasEstimadas": 1}, {"nombre": "Modularidad, encapsulación, interfaces y gestión del acoplamiento en software de supervisión y control (incluye diseño de APIs y separación de responsabilidades)", "horasEstimadas": 1}, {"nombre": "Pruebas, integración continua y despliegue (CI/CD) en entornos industriales: estrategias de testing, pipelines, contenedores y consideraciones de seguridad y disponibilidad", "horasEstimadas": 1}], "titulo": "Fundamentos y prácticas esenciales para arquitecturas de software en sistemas de supervisión y control industrial", "unidad": 1}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "usage": {"input_tokens": 1152, "total_tokens": 2870, "output_tokens": 1718, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 960}}, "responseId": "resp_023b7d45966ee21c00699f98be456881a0b4d4c94ad6ff9824", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Patrones de diseño, modularidad, pruebas y CI/CD aplicados a software de supervisión y control industrial."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-26 00:50:04.132967+00', '2026-03-25 23:09:29.105343+00', 3, 6, 'borrador', '[]', NULL, '''1'':309B,333B,356B,374B ''10'':53B ''20'':47B ''25'':30B ''40'':40B ''5'':60B ''a'':293B ''academico'':242B ''acoplamiento'':317B ''actividades'':58B,171B,235B ''al'':217B ''and'':303B ''apis'':327B ''aplicables'':216B ''aplicados'':292B ''aplicando'':83