	('2f5cf4c4-2f5d-4508-a520-adb340a709d2', '3ebc1d1c-e950-4a6e-948f-bb89efa40e77', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MKT-ATR311', 'Modelos de atribución omnicanal y optimización', 'OPTATIVA', 6, 8, 'b7eabdba-839c-430c-b390-97a314ba04e3', NULL, '{"ciclo": "Optativa", "clave_de_la_asignatura": "MKT-ATR311", "criterios_de_evaluacion": "Proyecto final de modelado y optimización omnicanal (40%); Laboratorios prácticos y entregables de modelado (30%); Evaluaciones parciales y quizzes sobre conceptos y métodos (20%); Participación en clase, discusión de casos y asistencia (10%). Total: 100%.", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante comprenderá y aplicará métodos estadísticos y de machine learning para atribuir conversiones entre canales, estimar ROI y diseñar estrategias de optimización de presupuesto publicitario en entornos omnicanal. Podrá preparar y limpiar datos multifuente, seleccionar y entrenar modelos de atribución, validar resultados, interpretar métricas de desempeño y proponer asignaciones de presupuesto basadas en evidencia para mejorar la eficiencia publicitaria. Esta formación contribuye al perfil de egreso orientado a la analítica de marketing y la toma de decisiones basada en datos.", "modalidades_tecnologicas_e_informaticas": "Se emplearán herramientas y recursos tecnológicos como Python (pandas, scikit-learn, statsmodels), R (opcional), entornos Jupyter/Colab, plataformas de visualización (Tableau, Power BI, matplotlib/seaborn), acceso a APIs de plataformas publicitarias (Google Ads, Meta), sistemas de gestión de datos (CSV/Parquet, bases de datos SQL), entornos de cómputo en la nube para procesamiento y, cuando sea necesario, herramientas para experimentación y A/B testing. Para la modalidad mixta o no escolarizada, se requerirá acceso estable a internet, repositorios Git y entorno de ejecución remoto.", "actividades_de_aprendizaje_independientes": "Se estiman 8 horas independientes para: revisión de lecturas y artículos académicos sobre modelos de atribución; prácticas de limpieza y preparación de datasets omnicanal; implementación y ajuste de modelos estadísticos y de ML; análisis e interpretación de resultados; preparación del proyecto final de optimización de presupuesto; participación en foros y revisión de materiales complementarios.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Modelos de atribución omnicanal y optimización", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Durante las 4 horas académicas se desarrollarán clases magistrales sobre teoría y métodos, sesiones guiadas de laboratorio con datasets reales o simulados, análisis de casos prácticos de atribución omnicanal, demostraciones de implementación de modelos y tutoría directa para el proyecto final; además se promoverán discusiones críticas sobre limitaciones y consideraciones éticas en el uso de datos."}', '[{"temas": [{"nombre": "Fundamentos de atribución: objetivos, métricas clave y limitaciones", "horasEstimadas": 1}, {"nombre": "Fuentes de datos, tracking omnicanal y limpieza/preprocesamiento", "horasEstimadas": 1}], "titulo": "Fundamentos y preparación de datos para atribución omnicanal", "unidad": 1}, {"temas": [{"nombre": "Modelos estadísticos y de machine learning para atribución (Markov, regresión, uplift, modelos basados en eventos)", "horasEstimadas": 1}, {"nombre": "Medición de ROI, validación de modelos y métodos de optimización de presupuesto omnicanal", "horasEstimadas": 1}], "titulo": "Modelado y optimización de presupuesto", "unidad": 2}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "responseId": "resp_0484fafb6df3c7340069a2183cc61481938c722b5997bfdfb8"}, "iaConfig": {"archivosAdjuntos": [], "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Métodos estadísticos y de machine learning para atribuir conversiones entre canales, medir ROI y optimizar presupuesto publicitario omnicanal."}, "generado_por": "ai_generate_subject_unified"}', 