	('d977175f-e22b-4b1e-b0ed-3d6f048b7929', '26806567-c5ee-404e-8f90-0f0711c21ea0', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'ALF-1', 'Alfabetización digital', 'OBLIGATORIA', 1, 1, NULL, NULL, '{"ciclo": "Ciclo I", "contenido_tematico": "1. Fundamentos de alfabetización digital en el ámbito jurídico; 1.1 Competencias digitales para profesionales del derecho; 1.2 Ética, seguridad y privacidad en entornos digitales legales; 2. Tecnologías aplicadas al derecho; 2.1 Gestión documental y evidencias digitales en procesos judiciales; 2.2 Búsqueda y recuperación de información jurídica con herramientas tecnológicas; 2.3 Firma digital, autenticación y certificaciones en contratos y evidencias; 3. Análisis de datos y jurisprudencia con tecnologías; 3.1 Herramientas de análisis de jurisprudencia y revisión de sentencias; 3.2 Inteligencia artificial y su uso en asesoría e investigación legal: beneficios, límites y consideraciones éticas; 4. Gobernanza de datos y cumplimiento normativo en tecnología legal; 4.1 Protección de datos personales y cumplimiento normativo (p. ej., RGPD); 4.2 Propiedad intelectual y licenciamiento de software legal tech; 5. Prácticas y proyectos de alfabetización digital en escenarios legales; 5.1 Estudio de caso, simulación y proyecto aplicado.", "clave_de_la_asignatura": "ALF-1", "criterios_de_evaluacion": "1) Participación activa en debates y ejercicios (10%). 2) Trabajo práctico con herramientas de derecho tecnológico (40%). 3) Ensayo analítico sobre un caso que involucra tecnología en derecho (20%). 4) Examen o proyecto final que demuestre integración de contenidos (30%).", "fines_de_aprendizaje_o_formacion": "Que el estudiante sea capaz de identificar y usar tecnologías relevantes para la práctica legal (gestión documental, búsquedas jurídicas, firma digital); aplicar criterios de ética y protección de datos en entornos digitales; analizar información jurídica mediante herramientas tecnológicas y elaborar un informe crítico; colaborar y comunicar resultados en equipos con tecnologías legales.", "modalidades_tecnologicas_e_informaticas": "Se utilizarán plataformas de gestión de aprendizaje (LMS), software de gestión documental y evidencia digital, herramientas de búsqueda jurídica, bases de datos legales, software de firma digital, herramientas de análisis de jurisprudencia y IA legal, entornos de colaboración y entornos seguros para manejo de datos. Para modalidades no escolarizada o mixta, se requerirá acceso a estas herramientas en línea.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas sobre fundamentos de alfabetización digital en derecho. Ejercicios prácticos independientes con gestión de documentos legales, búsqueda y análisis de jurisprudencia, ejercicios de firma digital y protección de datos. Desarrollo de un mini-proyecto: selección de una temática jurídica y aplicación de herramientas tecnológicas para elaborar un informe.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Alfabetización digital", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales con ejemplos de casos; talleres prácticos guiados para usar herramientas legales; análisis de casos con evidencia digital; supervisión de proyectos prácticos para aplicar tecnologías legales; revisión y retroalimentación de informes."}', '[{"temas": [{"nombre": "Competencias digitales para profesionales del derecho2", "horasEstimadas": 0}, {"nombre": "Ética, seguridad y privacidad en entornos digitales legales", "horasEstimadas": 0}], "titulo": "Fundamentos de alfabetización digital en el ámbito jurídico", "unidad": 1}, {"temas": [{"nombre": "Gestión documental y evidencias digitales en procesos judiciales", "horasEstimadas": 0}, {"nombre": "Búsqueda y recuperación de información jurídica con herramientas tecnológicas", "horasEstimadas": 0}, {"nombre": "Firma digital, autenticación y certificaciones en contratos y evidencias", "horasEstimadas": 0}], "titulo": "Tecnologías aplicadas al derecho", "unid