	('4f147b56-c22c-4363-9db5-5c13d5a9605f', '3ebc1d1c-e950-4a6e-948f-bb89efa40e77', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MKT-GDP210', 'Gobernanza de datos y privacidad para marketing', 'OBLIGATORIA', 5, 7, 'b7eabdba-839c-430c-b390-97a314ba04e3', NULL, '{"ciclo": "6 (Sexto ciclo)", "clave_de_la_asignatura": "MKT-GDP210", "criterios_de_evaluacion": "Proyecto de diseño de política y plan de cumplimiento (30%), Práctica de auditoría de modelo y reporte técnico (25%), Examen teórico sobre marco legal y técnicas (20%), Actividades y participación en clase (10%), Trabajos y estudios de caso independientes (15%). Total: 100%", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante podrá: 1) Identificar y aplicar los marcos legales relevantes para la protección de datos en actividades de marketing. 2) Diseñar y justificar técnicas de anonimización y minimización adecuadas a distintos escenarios de datos de marketing. 3) Implementar mecanismos de gestión de consentimiento y registros de tratamiento conforme a la normativa. 4) Realizar auditorías básicas de modelos predictivos para detectar riesgos de privacidad y sesgos, y proponer medidas correctivas. 5) Elaborar políticas internas de gobernanza de datos que integren cumplimiento legal y buenas prácticas operativas en estudios de mercado y campañas.", "modalidades_tecnologicas_e_informaticas": "Se empleará el Aula virtual (LMS) para distribución de material y evaluaciones; herramientas de análisis de datos y anonimización (p. ej., Python/R con bibliotecas de privacidad, ARX o herramientas equivalentes); plataformas de gestión de consentimiento (CMP), entornos de colaboración (Google Workspace/Office 365), repositorios para documentación de políticas y registros (Git/GitHub o soluciones documentales institucionales) y simuladores o entornos controlados para auditoría de modelos. Se recomienda acceso a navegadores actualizados y conexión estable a internet.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas de legislación y guías (GDPR, CCPA, LOPD); análisis de estudios de caso; ejercicios prácticos de anonimización y pruebas de reidentificación en datasets de ejemplo; elaboración y revisión de borradores de políticas de gobernanza; preparación del proyecto final y del informe de auditoría de modelo.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Gobernanza de datos y privacidad para marketing", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales sobre marco legal y conceptos clave; seminarios de discusión de casos reales; talleres prácticos de anonimización y uso de herramientas; laboratorios para auditoría de modelos y generación de reportes; presentaciones de propuestas de políticas y retroalimentación guiada por el docente."}', '[{"temas": [{"nombre": "Regulaciones internacionales y nacionales (GDPR, LOPD, CCPA) y principios de privacidad aplicables al marketing", "horasEstimadas": 1}], "titulo": "Marco legal y regulatorio para la protección de datos en marketing", "unidad": 1}, {"temas": [{"nombre": "Anonimización, seudonimización, minimización de datos, cifrado y seguridad en almacenamiento/transferencia", "horasEstimadas": 1}], "titulo": "Técnicas y buenas prácticas para protección y anonimización de datos", "unidad": 2}, {"temas": [{"nombre": "Gestión de consentimiento, registros de actividades de tratamiento, auditoría de modelos de ML y diseño/implantación de políticas internas", "horasEstimadas": 1}], "titulo": "Consentimiento, auditoría de modelos y políticas internas de cumplimiento", "unidad": 3}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "responseId": "resp_049e28f94084fd560069a2183c7bd881a1a7560b56b5a6a6b0"}, "iaConfig": {"archivosAdjuntos": [], "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Marco legal y prácticas para protección de datos, anonimización, consentimiento y auditoría de modelos; políticas internas y cumplimiento en estudios de mercado."}, "generad