rasEstimadas": 3}, {"nombre": "Identificación de tesis, supuestos y conclusiones", "horasEstimadas": 3}, {"nombre": "Vocabulario y expresiones frecuentes en el discurso jurídico", "horasEstimadas": 2}], "titulo": "Lectura crítica de textos jurídicos", "unidad": 1}, {"temas": [{"nombre": "Estructura de normas, leyes y actos administrativos", "horasEstimadas": 3}, {"nombre": "Métodos de interpretación jurídica y análisis de casos", "horasEstimadas": 3}, {"nombre": "Fuentes del derecho y su lectura crítica", "horasEstimadas": 2}], "titulo": "Interpretación y estructura normativa", "unidad": 2}, {"temas": [{"nombre": "Construcción de párrafos claros y coherentes", "horasEstimadas": 3}, {"nombre": "Precisión léxica y uso adecuado de la terminología jurídica", "horasEstimadas": 3}, {"nombre": "Estilo jurídico: concisión, objetividad y formalidad", "horasEstimadas": 2}], "titulo": "Fundamentos de la redacción jurídica", "unidad": 3}, {"temas": [{"nombre": "Redacción de demandas y escritos procesales", "horasEstimadas": 3}, {"nombre": "Redacción de contratos y cláusulas", "horasEstimadas": 3}, {"nombre": "Elaboración y análisis de autos, resoluciones y acuerdos", "horasEstimadas": 2}], "titulo": "Redacción de documentos jurídicos específicos", "unidad": 4}, {"temas": [{"nombre": "Estructura del argumento jurídico: premisas, razonamiento y conclusión", "horasEstimadas": 3}, {"nombre": "Técnicas de persuasión y sustentación probatoria", "horasEstimadas": 3}, {"nombre": "Refutación y manejo de contra-argumentos", "horasEstimadas": 2}], "titulo": "Argumentación jurídica y persuasión escrita", "unidad": 5}, {"temas": [{"nombre": "Presentaciones orales y defensa de escritos jurídicos", "horasEstimadas": 3}, {"nombre": "Revisión, corrección y edición de textos jurídicos", "horasEstimadas": 3}, {"nombre": "Normas de citación, formato y manejo de referencias legales", "horasEstimadas": 2}], "titulo": "Comunicación oral y edición profesional", "unidad": 6}]', 'IA', '{"ai": {"model": 