	('e20db97a-7fe0-4d87-a47d-247a74dcc0de', '58e11252-0491-4b7d-8757-8793a6f60617', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LD-DF-103', 'Introducción al Sistema Financiero Mexicano', 'TRONCAL', 5, 2, 'ff7cc595-6291-4177-b323-1dc5c902b6ea', NULL, '{"ciclo": "Troncal", "clave_de_la_asignatura": "LD-DF-103", "fines_de_aprendizaje_o_formacion": "Que el estudiante comprenda la estructura, funcionamiento y marco regulatorio del sistema financiero mexicano; identifique funciones y riesgos de bancos, casas de bolsa, aseguradoras y entidades reguladoras; analice políticas públicas y prácticas regulatorias; y desarrolle capacidad para evaluar instituciones financieras y proponer soluciones o mejoras en contextos reales.", "modalidades_tecnologicas_e_informaticas": "Uso de plataforma educativa (LMS) para entrega de materiales y tareas; acceso a fuentes oficiales (Banxico, CNBV, CONSAR, SHCP) y bases de datos públicas; herramientas ofimáticas para elaboración de trabajos (procesador de texto, hojas de cálculo); herramientas de presentación y, de ser posible, plataformas de simulación de mercados o demostraciones de trading/operaciones.", "actividades_de_aprendizaje_independientes": "Lectura y análisis de leyes y normativas; estudio de informes y estadísticas de Banxico y CNBV; elaboración de estudios de caso y proyectos integradores; resolución de ejercicios prácticos sobre productos financieros; preparación de presentaciones y trabajos de investigación sobre instituciones específicas.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Introducción al Sistema Financiero Mexicano", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y exposiciones guiadas; análisis y discusión de casos reales; sesiones de resolución de ejercicios y talleres prácticos; seminarios con especialistas o invitados; retroalimentación dirigida para el proyecto integrador y orientación en el uso de fuentes y datos oficiales."}', '[{"temas": [{"nombre": "Concepto y funciones del sistema financiero", "horasEstimadas": 3}, {"nombre": "Evolución histórica y marco jurídico", "horasEstimadas": 3}, {"nombre": "Participantes y estructura institucional", "horasEstimadas": 4}], "titulo": "Panorama y marco legal del sistema financiero mexicano", "unidad": 1}, {"temas": [{"nombre": "Estructura y tipos de bancos", "horasEstimadas": 5}, {"nombre": "Productos y servicios bancarios (crédito, ahorro y pagos)", "horasEstimadas": 5}, {"nombre": "Riesgos bancarios y supervisión", "horasEstimadas": 4}], "titulo": "Banca y operaciones bancarias", "unidad": 2}, {"temas": [{"nombre": "Casas de bolsa y mercado de valores", "horasEstimadas": 6}, {"nombre": "Aseguradoras y productos de seguros", "horasEstimadas": 5}, {"nombre": "Administradoras de fondos para el retiro (AFORE) y pensiones", "horasEstimadas": 4}, {"nombre": "Entidades de microfinanzas y SOFIPOs", "horasEstimadas": 3}], "titulo": "Intermediarios y mercados de capital", "unidad": 3}, {"temas": [{"nombre": "Principales reguladores: Banxico, CNBV, CONSAR, CNSF y sus funciones", "horasEstimadas": 5}, {"nombre": "Política monetaria, estabilidad financiera y resolución bancaria", "horasEstimadas": 4}, {"nombre": "Protección al consumidor financiero y prevención de lavado de dinero", "horasEstimadas": 3}, {"nombre": "Tendencias e innovación financiera: fintech e inclusión financiera", "horasEstimadas": 2}], "titulo": "Regulación, estabilidad y retos contemporáneos", "unidad": 4}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "responseId": "resp_0e10e4aad54f12b80069b3fcd32f1881978d0c130a09e77d01"}, "iaConfig": {"archivosAdjuntos": [], "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Estructura e instituciones del sistema financiero nacional, funciones de bancos, casas de bolsa, aseguradoras y reguladores."}, "generado_por": "ai_generate_subject_unified"}', NULL, NULL, '2026-03-13 12:02:21.800341+00', '2026-03-25 23:09:29.105343+00', 56, 84, 'borrador', '[{"criterio": "Exámene