	('1697248e-dae0-4e81-97fe-5a2674035b5e', '58e11252-0491-4b7d-8757-8793a6f60617', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'mat01', 'Matemáticas Financieras Avanzadas', 'TRONCAL', 5, NULL, NULL, NULL, '{"ciclo": "Troncal", "clave_de_la_asignatura": "mat01", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante será capaz de aplicar herramientas matemáticas avanzadas y técnicas computacionales para modelar, valuar y gestionar instrumentos financieros complejos; interpretar y calibrar modelos de tasas e instrumentos derivados; diseñar estrategias cuantitativas de gestión de riesgo y llevar a cabo un proyecto integrador que demuestre competencia en implementación, validación y comunicación técnica. Esta formación corresponde a una materia de matemáticas aplicada a finanzas de nivel avanzado (troncal), distinta de introducciones básicas al área.", "modalidades_tecnologicas_e_informaticas": "Se utilizarán plataformas de cálculo y programación (Python, R o MATLAB), bibliotecas para análisis numérico y financiero (pandas, numpy, scipy, QuantLib u equivalentes), entornos de control de versiones (Git), plataformas para simulación y visualización de datos, y recursos en línea (repositorios académicos y bases de datos financieras). Se recomienda acceso a computadoras con capacidad para simulaciones y librerías científicas instaladas.", "actividades_de_aprendizaje_independientes": "Resolución de problemas y ejercicios avanzados, desarrollo y prueba de código para modelos financieros, lectura crítica de artículos especializados y documentación técnica, preparación del proyecto integrador que incluye recolección de datos, calibración de modelos, simulaciones y elaboración de reporte técnico y presentación.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "matemáticas", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales enfocadas en fundamentos teóricos y demostraciones selectas, sesiones prácticas guiadas en laboratorio para implementación de modelos, seminarios de discusión de casos y literatura, talleres de calibración y validación de modelos, tutorías para avance y revisión del proyecto integrador, evaluaciones parciales supervisadas."}', '[{"temas": [{"nombre": "Repaso avanzado de álgebra financiera y análisis funcional", "horasEstimadas": 3}, {"nombre": "Series temporales y procesos estocásticos elementales para finanzas", "horasEstimadas": 3}, {"nombre": "Métodos numéricos y aproximaciones: interpolación, integración y soluciones de ecuaciones no lineales", "horasEstimadas": 3}], "titulo": "Fundamentos matemáticos avanzados aplicados a finanzas", "unidad": 1}, {"temas": [{"nombre": "Curvas de rendimiento, construcción y suavizado", "horasEstimadas": 3}, {"nombre": "Modelos de tasas a plazo y de cortos plazos (Vasicek, CIR) y su calibración", "horasEstimadas": 2}, {"nombre": "Técnicas avanzadas de descuento y valuación de flujos complejos", "horasEstimadas": 2}], "titulo": "Estructura de tasas de interés y valuación avanzada", "unidad": 2}, {"temas": [{"nombre": "Modelos de valuación de derivados: enfoques deterministas y estocásticos", "horasEstimadas": 3}, {"nombre": "Precios bajo medidas equivalentes y cambio de medida (Girsanov) — conceptual", "horasEstimadas": 2}, {"nombre": "Valoración numérica de opciones exóticas y barrera; esquemas de Monte Carlo avanzados y reducción de varianza", "horasEstimadas": 2}], "titulo": "Derivados y teoría de precios en mercados incompletos", "unidad": 3}, {"temas": [{"nombre": "Medidas de riesgo (VaR, CVaR) y sus propiedades matemáticas", "horasEstimadas": 3}, {"nombre": "Optimización de portafolios con restricciones y técnicas de optimización no lineal", "horasEstimadas": 2}, {"nombre": "Modelado de crédito y spread: conceptos y herramientas cuantitativas", "horasEstimadas": 2}], "titulo": "Riesgo, optimización y gestión cuantitativa", "unidad": 4}, {"temas": [{"nombre": "Implementación de modelos financieros avanzados en software (R/