	('0652ac2d-eb23-41d7-8f33-70ece0ff9d4c', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LESE202', 'Plataformas web para monitoreo y análisis de acompañamiento', 'OBLIGATORIA', 3, NULL, NULL, NULL, '{"ciclo": "4", "clave_de_la_asignatura": "LESE202", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante será capaz de diseñar, implementar y desplegar plataformas web orientadas al registro, visualización y análisis de datos de observación y progreso en contextos educativos. Podrá modelar datos adecuados, aplicar medidas de privacidad y seguridad, desarrollar interfaces y dashboards útiles para equipos educativos, y producir reportes y alertas que faciliten la toma de decisiones pedagógicas. Contribuye al perfil de egreso ofreciendo competencias técnicas y éticas para gestionar herramientas digitales de acompañamiento.", "modalidades_tecnologicas_e_informaticas": "Se emplearán frameworks web (por ejemplo Node.js/Django/Flask), bases de datos relacionales y NoSQL, librerías de visualización (D3, Chart.js, Plotly), herramientas de autenticación y gestión de identidades, entornos de desarrollo (IDE, Git), plataformas de despliegue (Heroku, AWS, DigitalOcean) y entornos de pruebas. Se utilizarán además gestores de proyectos colaborativos (GitHub/GitLab), herramientas de comunicación síncrona y asíncrona y simuladores de datos para prácticas. Estos recursos permiten el trabajo presencial y remoto según necesidades.", "actividades_de_aprendizaje_independientes": "Lecturas y estudio de documentación técnica sobre privacidad y diseño; desarrollo de actividades prácticas y tareas de programación; preparación de capítulos del proyecto integrador (modelado, backend, frontend, despliegue); pruebas de usabilidad con usuarios y elaboración de reportes; revisión de código y resolución de incidencias; presentaciones individuales y en equipo. Estimadas 24 horas independientes a lo largo del curso.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Plataformas web para monitoreo y análisis de acompañamiento", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales sobre conceptos y normativas; sesiones guiadas de laboratorio para diseño de bases de datos y APIs; talleres de visualización y construcción de dashboards; sesiones de revisión de proyectos y retroalimentación; actividades de evaluación práctica y presentación de avances; mentoría para despliegue y pruebas. Estas actividades se organizan para cubrir las 36 horas académicas y apoyar el desarrollo del proyecto integrador."}', '[{"temas": [{"nombre": "Introducción al monitoreo educativo y objetivos de acompañamiento", "horasEstimadas": 1}, {"nombre": "Principios de diseño centrado en usuarios y equipos educativos", "horasEstimadas": 1}, {"nombre": "Casos de uso, actores y especificación de requisitos funcionales y no funcionales", "horasEstimadas": 2}], "titulo": "hola", "unidad": 1}, {"temas": [{"nombre": "Modelado de datos para observación y registro de progreso", "horasEstimadas": 2}, {"nombre": "Privacidad, protección de datos personales y marco legal aplicable", "horasEstimadas": 2}, {"nombre": "Técnicas de anonimización, minimización de datos y gestión de permisos", "horasEstimadas": 2}], "titulo": "Modelado de datos y privacidad2", "unidad": 2}, {"temas": [{"nombre": "Arquitecturas web, diseño de APIs REST/GraphQL y endpoints para registro de observaciones", "horasEstimadas": 2}, {"nombre": "Selección y diseño de bases de datos relacionales y NoSQL para eventos y series temporales", "horasEstimadas": 2}, {"nombre": "Autenticación, autorización, roles y control de acceso", "horasEstimadas": 2}, {"nombre": "Integración de formularios, formularios móviles y captura offline/online", "horasEstimadas": 2}], "titulo": "Arquitectura backend y gestión de datos", "unidad": 3}, {"temas": [{"nombre": "Principios de diseño de interfaz para equipos educativos", "horasEstimadas": 2}, {"nombre": "Visualización de datos: gráficos, tablas y métricas clave", "horasEstimadas": 2}, {"nombre": "Dashboards interactivos, filtros y exploración de casos", "horasEstimadas": 2}, {"nombre": "Accesibilidad, usabilidad y pruebas con usuarios", "horasEstimadas": 2}], "titulo": "Interfaz, visualización y experiencia de usuario", "unidad": 4}, {"temas": [{"nombre": "Análisis descriptivo y métricas para seguimiento de progreso", "horasEstimadas": 2}, {"nombre": "Técnicas básicas de analítica, detección de tendencias y generación de alertas", "horasEstimadas": 2}, {"nombre": "Exportación de datos, generación de reportes y formatos interoperables", "horasEstimadas": 2}], "titulo": "Análisis, reportes y alertas", "unidad": 5}, {"temas": [{"nombre": "Despliegue, escalabilidad, backups y seguridad en producción", "horasEstimadas": 2}, {"nombre": "Prácticas colaborativas: control de versiones, CI/CD y documentación", "horasEstimadas": 1}, {"nombre": "Proyecto final: presentación, evaluación y retroalimentación", "horasEstimadas": 1}], "titulo": "Despliegue, mantenimiento y trabajo en equipo", "unidad": 6}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "responseId": "resp_077c5ee03ecf1cbb0069b2dc718ce481929d05dce5e238bb5f"}, "iaConfig": {"archivosAdjuntos": [], "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Creación y uso de plataformas web para registrar, visualizar y analizar datos de observación y progreso, garantizando privacidad y herramientas útiles para equipos educativos."}, "generado_por": "ai_generate_subject_unified"}', NULL, NULL, '2026-03-12 15:31:59.052425+00', '2026-03-25 23:09:29.105343+00', 36, 24, 'borrador', '[{"criterio": "Participación y actividades en sesiones dirigidas (laboratorio y taller)", "porcentaje": 15}, {"criterio": "Tareas y ejercicios prácticos (implementación de módulos y mini-proyectos)", "porcentaje": 29}, {"criterio": "Proyecto integrador: diseño, implementación y despliegue de una plataforma funcional", "porcentaje": 35}, {"criteri