	('33cba9ee-ad7d-438d-85b8-45ab67f1f40e', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION_CAMPO', 'denominacion_de_la_asignatura_o_unidad_de_aprendizaje', NULL, '"ejemplo2"', NULL, NULL),
	('1747d382-4891-4797-b315-4bbcda79e056', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION_CAMPO', 'actividades_de_aprendizaje_bajo_conduccion_de_un_academico', NULL, '"Clases magistrales y sesiones prácticas dirigidas para explicación de conceptos y herramientas; talleres guiados de análisis de datos y DOE; tutorías sobre selección y avance de proyectos; supervisión de pilotos y pruebas; retroalimentación estructurada a entregables y presentaciones; evaluación y defensa presencial o virtual de proyectos."', NULL, NULL),
	('8feee76d-7b2f-404e-a9c4-4f923331e94f', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION_CAMPO', 'clave_de_la_asignatura', NULL, '"w32423"', NULL, NULL),
	('9f38a999-1c44-4d6e-9422-3f241d3e0f2d', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION_CAMPO', 'modalidades_tecnologicas_e_informaticas', NULL, '"La asignatura empleará plataformas de gestión del curso (LMS) para entrega de materiales y evaluaciones, software estadístico (por ejemplo Minitab, R o Python pandas/statsmodels), hojas de cálculo avanzadas (Excel con complementos estadísticos), herramientas de videoconferencia para sesiones sincrónicas y revisión de proyectos, y repositorios colaborativos (Git/GitHub o carpetas en la nube) para el trabajo en equipo. Se fomentará el uso de simuladores y plantillas para MSA, DOE y cartas de control."', NULL, NULL),
	('38919321-772f-4d82-9acc-70702ae4bd6f', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION_CAMPO', 'ciclo', NULL, '"Optativa"', NULL, NULL),
	('4f8e583d-a392-475e-9034-0801d5906145', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION_CAMPO', 'actividades_de_aprendizaje_independientes', NULL, '"Estudio y lectura de materiales y artículos sobre Six Sigma y Lean; resolución de ejercicios estadísticos; preparación de reportes de avance del proyecto; análisis de datos reales o simulados; diseño y ejecución de experimentos en entornos controlados o simulados; elaboración de presentaciones y documentación de planes de control."', NULL, NULL),
	('bcfbdc18-f9f4-4483-937d-59cbce52c35a', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION_CAMPO', 'fines_de_aprendizaje_o_formacion', NULL, '"Al concluir la asignatura, el estudiante será capaz de aplicar el enfoque Six Sigma (principalmente DMAIC) para identificar, analizar y resolver problemas de calidad y procesos en organizaciones. Desarrollará competencias en recopilación y análisis de datos, uso de técnicas estadísticas y herramientas Lean, diseño de experimentos y elaboración de planes de control que permitan reducir la variabilidad y mejorar el desempeño de procesos, contribuyendo al perfil de egreso orientado a la mejora continua y la toma de decisiones basada en datos."', NULL, NULL),
	('a8fed34e-66a6-4bee-8c69-f1965020e995', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION', 'criterios_de_evaluacion', '[]', '[{"criterio": "Proyecto práctico Six Sigma (aplicación DMAIC en caso real o simulado)", "porcentaje": 40}, {"criterio": "Exámenes teórico-prácticos (parciales y final)", "porcentaje": 25}, {"criterio": "Tareas y estudios de caso / informes técnicos", "porcentaje": 15}, {"criterio": "Participación, discusiones en clase y actividades dirigidas", "porcentaje": 10}, {"criterio": "Presentación y defensa del proyecto / evaluación por pares", "porcentaje": 10}]', NULL, NULL),
	('4a0e0e7e-7a01-49c0-9c02-de11ad9d67d7', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 18:25:17.045142+00', 'ACTUALIZACION', 'contenido_tematico', '[]', '[{"temas": [{"nombre": "Origen, principios y objetivos de Six Sigma", "horasEstimadas": 8}, {"nombre": "Visión general de DMAIC y DMADV", "horasEstimadas": 8}, {"nombre": "Integración Lean-Six Sigma", "horasEstimadas": 6}, {"nombre": "Roles, estructura organizacional y despliegue (Champion, Black Belt, Green Belt)", "horasEstimadas": 6}, {"nombre": "Selección de proyectos y elaboración del project charter", "horasEstimadas": 12}], "titulo": "Introducción a Six Sigma y fundamentos del enfoque", "unidad": 1}, {"temas": [{"nombre": "Voz del cliente (VoC) y traducción a CTQ", "horasEstimadas": 12}, {"nombre": "Mapeo de procesos, SIPOC y diagramas de flujo", "horasEstimadas": 10}, {"nombre": "Planeación de recolección de datos y Análisis del sistema de medición (MSA)", "horasEstimadas": 16}, {"nombre": "Estadística descriptiva aplicada y índices de capacidad (Cp, Cpk)", "horasEstimadas": 12}, {"nombre": "Introducción a cartas de control y monitoreo de procesos", "horasEstimadas": 10}], "titulo": "Fase Definir y Medir: herramientas y recopilación de datos", "unidad": 2}, {"temas": [{"nombre": "Análisis de causa raíz: 5 Whys, diagrama de Ishikawa", "horasEstimadas": 12}, {"nombre": "Pruebas de hipótesis y su aplicación en mejora de procesos", "horasEstimadas": 12}, {"nombre": "Análisis de regresión y correlación para identificar relaciones críticas", "horasEstimadas": 12}, {"nombre": "ANOVA y análisis multivariado aplicado a problemas de calidad", "horasEstimadas": 12}, {"nombre": "Introducción práctica al diseño de experimentos (DOE)", "horasEstimadas": 12}], "titulo": "Fase Analizar: técnicas estadísticas y análisis de causas", "unidad": 3}, {"temas": [{"nombre": "Generación y priorización de ideas de mejora (KAIZEN, brainstorming, matriz Pugh)", "horasEstimadas": 8}, {"nombre": "Diseño de experimentos (DOE) avanzado y casos prácticos", "horasEstimadas": 12}, {"nombre": "Herramientas Lean para eliminación de desperdicios (5S, SMED, Value Stream Mapping)", "horasEstimadas": 8}, {"nombre": "Planificación de implementación y pruebas piloto", "horasEstimadas": 8}, {"nombre": "Evaluación de riesgos y uso de FMEA en mejoras", "horasEstimadas": 8}], "titulo": "Fase Mejorar: generación de soluciones y herramientas Lean", "unidad": 4}, {"temas": [{"nombre": "Elaboración de planes de control y gestión visual", "horasEstimadas": 8}, {"nombre": "Implementación de control estadístico de procesos (SPC)", "horasEstimadas": 8}, {"nombre": "Estandarización, documentación y capacitación", "horasEstimadas": 6}, {"nombre": "Mecanismos para sostener mejoras y cultura de mejora continua", "horasEstimadas": 8}], "titulo": "Fase Control: estandarización y sostenibilidad de mejoras", "unidad": 5}]', NULL, NULL),
	('d7ee00db-0ec8-4360-b171-18de00298474', '0befc6c4-cdfd-4288-9ab6-e98060e8d1d5', NULL, '2026-04-28 21:45:41.565984+00', 'ACTUALIZACION', 'numero_ciclo', NULL, '2', NULL, NULL),
