	('83eb3289-0b3a-44aa-b1bc-97fa38c76ad3', '58e11252-0491-4b7d-8757-8793a6f60617', NULL, '2026-01-30 22:21:06.594763+00', 'CREACION', NULL, NULL, '{"id": "58e11252-0491-4b7d-8757-8793a6f60617", "datos": {"vigencia": "2026-2031", "area_de_estudio": "Derecho Financiero y Ciencias Jurídicas", "perfil_de_egreso": "El egresado de la Licenciatura en Derecho Financiero habrá adquirido una competencia integral para operar, regular y supervisar operaciones financieras institucionales. Conocimientos: dominio profundo de la normativa CNBV, AML/CTF, regulación de bancos, valores y almacenes de depósito; habilidades: análisis integral de estados contables, interpretación de marcos regulatorios y diseño de soluciones de cumplimiento; actitudes: ética profesional, responsabilidad social, capacidad de toma de decisiones y trabajo colaborativo en entornos multidisciplinarios.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "El aspirante debe presentar Bachillerato completo, preferentemente con orientación en Ciencias Sociales o Humanidades, con base en conocimientos de razonamiento lógico, matemáticas financieras y nociones básicas de derecho; se valora la experiencia de aprendizaje autónomo y la capacidad de lectura crítica, así como habilidades de comunicación oral y escrita para argumentación jurídica y financiera.", "curso_propedeutico": null, "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato general con orientación en Ciencias Sociales o equivalente; se requiere certificado de calificaciones y acreditación de aprobación de asignaturas clave como Historia, Economía, Matemáticas y Literatura; se consideran equivalencias académicas para estudiantes procedentes de sistemas educativos extranjeros.", "carga_horaria_a_la_semana": 18, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "LD-DF-2026-09", "duracion_del_ciclo_escolar": "18", "fines_de_aprendizaje_o_formacion": "Analizar marcos regulatorios CNBV y de valores; Aplicar principios contables y normativos a operaciones de bancos, valores y depósitos; Diseñar estructuras de gobierno corporativo y gestión de riesgos dentro de entidades financieras; Evaluar cumplimiento normativo, auditoría, control interno y reporting; Interpretar estados financieros, balances y flujos de efectivo para la toma de decisiones estratégicas; Implementar prácticas de supervisión y control de operaciones financieras; Comunicar hallazgos y recomendaciones a directivos, reguladores y partes interesadas.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Derecho Financiero", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El sustento teórico del modelo curricular se apoya en fundamentos de diseño por competencias, constructivismo pedagógico y marcos de regulación financiera contemporánea. Se integra la contabilidad gerencial, la administración estratégica y las finanzas para desarrollar un profesional capaz de analizar, regular y gestionar entidades financieras, bancos, casas de bolsa y almacenes de depósito, con enfoque en ética, responsabilidad y sostenibilidad institucional.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "La administración del plan se consolida mediante un comité académico responsable de la coordinación de cada bloque disciplinar y la supervisión de la carga horaria. En un diseño flexible se define un mínimo y máximo de asignaturas por ciclo, con control de avances a través de un sistema de gestión académica, portafolios y rúbricas. Se mantiene la coordinación entre Derecho, Contabilidad, Finanzas y Administración para garantizar la coherencia entre contenidos, prácticas y resultados de aprendizaje, así como la operación logística y tecnológica que sostiene el programa.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "La propuesta de evaluación periódica contempla revisión anual de indicadores de desempeño, análisis de resultados de aprendizaje por asignatura mediante rúbricas estandarizadas, retroalimentación de estudiantes, docentes y empleadores, y ajuste del plan de estudio en función de necesidades disciplinares y regulatorias. Se utilizarán mecanismos de calidad educativa, estadísticas de retención y satisfacción, así como auditorías internas para garantizar la vigencia y pertinencia del programa.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}, "nivel": "Licenciatura", "activo": true, "nombre": "Licenciatura en Derecho Financiero", "creado_en": "2026-01-30T22:21:06.594763+00:00", "plan_hash": "1f8babc6e77d424255212389", "carrera_id": "170f14c6-1b9f-49a7-92f0-ccf79c41d750", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Los textos deben ser largos con una extensión de al menos de 100 caracteres", "descripcionEnfoqueAcademico": "Derecho financiero enfocado en las reglas de operación que dicta la comisión nacional bancaria y de valores para la creación de bancos, valores y almacenes de depósito, que incluya una parte de contabilidad, administración de empresas y finanzas."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3616, "total_tokens": 12863, "output_tokens": 9247, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 8320}}, "responseId": "resp_0c0739997e516d7200697d2e87677481938e30a85639df4894", "conversationId": null}}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "licenciatura en derecho financiero", "numero_ciclos": 9, "actualizado_en": "2026-01-30T22:21:06.594763+00:00", "actualizado_por": null, "conversation_id": null, "estado_actual_id": 