	('097b05ec-1e3d-4c75-94cc-3f239608331f', '6d1ad1d6-f34b-45fe-8b7c-3aef45d84901', NULL, '2026-02-05 22:31:19.285198+00', 'CREACION', NULL, NULL, '{"id": "6d1ad1d6-f34b-45fe-8b7c-3aef45d84901", "datos": {"vigencia": "2026-2031", "area_de_estudio": "Educación", "perfil_de_egreso": "Conocimientos: fundamentos de educación, teorías didácticas, políticas públicas en educación, evaluación educativa, investigación educativa, ética profesional; Habilidades: diseño curricular y planificación de unidades didácticas; implementación de estrategias de enseñanza; uso de TIC; evaluación y retroalimentación; investigación educativa; liderazgo y gestión de proyectos; comunicación eficaz; trabajo colaborativo; Actitudes: ética profesional, inclusión y equidad, responsabilidad social, aprendizaje continuo, flexibilidad, valoración de la diversidad.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Conocimientos previos en fundamentos de la educación, psicología del desarrollo y sociología de la educación; Habilidades: lectura crítica, escritura académica, comunicación oral, manejo básico de tecnologías; Aptitudes: interés por la docencia, responsabilidad, trabajo en equipo, adaptabilidad y pensamiento crítico.", "curso_propedeutico": null, "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido; preferentemente en áreas de ciencias sociales, humanidades o educación; se valorará experiencia de servicio comunitario o educativa; para el ingreso se deben cumplir los requisitos institucionales de Universidad La Salle México.", "carga_horaria_a_la_semana": 22, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "PL-EDU-LAS-2026-CEDU", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Analizar enfoques y teorías de la educación para fundamentar prácticas pedagógicas en contextos educativos; Diseñar intervenciones curriculares, planes de evaluación y proyectos de desarrollo docente; Implementar estrategias de enseñanza y evaluación formativa para fomentar el aprendizaje profundo; Desarrollar materiales didácticos y recursos digitales accesibles para diversos contextos; Evaluar procesos de enseñanza-aprendizaje y resultados de aprendizaje para la mejora continua; Aplicar metodologías de investigación educativa para diagnosticar problemáticas y proponer soluciones.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ciencias de la Educación (2026)", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El modelo curricular se fundamenta en un enfoque por competencias basado en el constructivismo sociocultural; incorpora aprendizaje basado en proyectos, prácticas docentes, evaluación auténtica y desarrollo de capacidades docentes; integra uso de tecnologías de la información y comunicación y principios de equidad e inclusión.", "justificacion_de_la_propuesta_curricular": "La propuesta curricular responde a la necesidad de formar docentes capaces de diseñar, implementar y evaluar procesos educativos de calidad, con atención a la diversidad, equidad y uso de tecnologías, en concordancia con el Acuerdo 17/11/17 y la orientación institucional de la Universidad La Salle México.", "administracion_y_operatividad_del_plan_de_estudios": "La administración del plan recae en la Dirección de la Facultad de Ciencias de la Educación, con apoyo del Comité Curricular. Se define un calendario académico por ciclo, manejo de créditos y requisitos de progresión, y un sistema de gestión académica para registrar asignaturas y resultados. Se establecen políticas de matrícula, asignación de docentes a asignaturas y evaluación institucional, con revisión semestral de indicadores de aprendizaje y planes de mejora.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Realizar evaluación anual del plan con indicadores de desempeño académico, retención y empleabilidad. Ejecutar revisión semestral de contenidos y estrategias didácticas para asegurar relevancia y actualidad. Documentar hallazgos y acciones de mejora para su implementación en el siguiente ciclo.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}, "nivel": "Licenciatura", "activo": true, "nombre": "Ciencias de la Educación (2026)", "creado_en": "2026-02-05T22:31:19.285198+00:00", "plan_hash": "3178f8f055b4bee439a7d9df", "carrera_id": "e7b89d58-6b55-4993-a96f-bb4eb8c2eb88", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Genera un plan de estudios realista y detallado."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3567, "total_tokens": 15045, "output_tokens": 11478, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 10624}}, "responseId": "resp_0ca298e3df0fcf9300698519d9d4508197b20bf87ea630d208", "conversationId": null}}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "ciencias de la educacion (2026)", "numero_ciclos": 9, "actualizado_en": "2026-02-05T22:31:19.285198+00:00", "actualizado_por": null, "conversation_id": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
