	('b40ec03f-9c9f-4b2f-8aee-016d25082ac6', '26806567-c5ee-404e-8f90-0f0711c21ea0', NULL, '2026-02-09 15:04:15.579361+00', 'CREACION', NULL, NULL, '{"id": "26806567-c5ee-404e-8f90-0f0711c21ea0", "datos": {"vigencia": "2026-2031", "area_de_estudio": "Ciencias Sociales y Jurídicas", "perfil_de_egreso": "Conocimientos: fundamentos del derecho civil, mercantil, constitucional y administrativo; regulación de tecnologías de la información, protección de datos personales, propiedad intelectual y ciberseguridad; Habilidades: analizar, redactar, asesorar y litigar en entornos digitales; diseñar políticas de cumplimiento, contratos y términos de uso para plataformas; evaluar riesgos y gestionar cumplimiento normativo (compliance) en empresas tecnológicas; Actitudes: ética profesional, pensamiento crítico, responsabilidad social, adaptabilidad y aprendizaje continuo ante cambios tecnológicos.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Conocimientos previos: nociones de derecho básico, cultura general y fundamentos de ética; habilidades: lectura crítica, redacción formal, argumentación y razonamiento lógico; aptitudes: capacidad de análisis, pensamiento estructurado, trabajo en equipo y comunicación efectiva; competencias tecnológicas básicas: manejo de herramientas ofimáticas, navegación segura, búsqueda de información y uso de plataformas de aprendizaje; condiciones para el ingreso: Bachillerato concluido y predisposición para el estudio presencial y el aprendizaje orientado a proyectos; se valorará interés por la regulación tecnológica y la protección de datos.", "curso_propedeutico": "Curso propedéutico para aspirantes con antecedentes no jurídicos; duración de 2 a 4 semanas; contenidos: introducción al derecho, terminología básica, fundamentos de tecnología y alfabetización digital; relación con el plan de estudios: orientación para la trayectoria semestral y acceso a la plataforma institucional.", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido; para ingreso a Licenciatura en Derecho Digital.", "carga_horaria_a_la_semana": 20, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "DLD-LIC-DIG-2026", "duracion_del_ciclo_escolar": "18 semanas", "fines_de_aprendizaje_o_formacion": "Analizar fundamentos teóricos del derecho aplicados al entorno digital y a plataformas en línea; Aplicar normativas de protección de datos personales, privacidad y seguridad de la información en operaciones digitales; Diseñar contratos, políticas de uso y términos de servicio para plataformas y servicios digitales; Evaluar impactos éticos y sociales de la digitalización en derechos fundamentales y en prácticas empresariales; Elaborar políticas de privacidad, avisos de cookies, cláusulas de tratamiento de datos y estrategias de responsabilidad por datos; Proponer estrategias de cumplimiento normativo (compliance) para organizaciones tecnológicas y start-ups; Desarrollar habilidades de litigio, negociación y mediación en contextos de derecho digital; Integrar marcos nacionales e internacionales para la regulación de tecnologías emergentes.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura; Licenciatura en Derecho Digital", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "Fundamento teórico: modelo curricular basado en aprendizaje por competencias, con enfoque constructivista social y aprendizaje situado; se apoya en teorías de derecho, tecnología y ética; integra componentes de aprendizaje activo, proyectos de investigación y prácticas profesionales supervisadas; se apoya en marcos de calidad educativa y en la innovación pedagógica para educación superior; la selección de contenidos y experiencias formativas se orienta a la resolución de problemas reales en entornos digitales con énfasis en la integridad académica; el diseño curricular se coordina con la metodología del Acuerdo 17/11/17 para garantizar coherencia con el marco normativo.", "justificacion_de_la_propuesta_curricular": "La propuesta curricular responde a la necesidad de formar profesionales del derecho capaces de enfrentar los retos jurídicos derivados de la digitalización de servicios, comercio electrónico, plataformas digitales y relaciones laborales en entornos digitales; busca una formación integral, transversal y actualizada que combine fundamentos jurídicos con conocimiento específico en tecnología y datos; se alinea con el perfil institucional de la Universidad La Salle y con el Acuerdo 17/11/17; utiliza una estructura de semestres para facilitar la progresión de competencias y la articulación entre teoría y práctica; incorpora tecnologías y herramientas digitales, fomentando la autogestión del aprendizaje y la disponibilidad de recursos para estudios en modalidad escolar; se propone un enfoque práctico y prospectivo para fortalecer la empleabilidad de los egresados.", "administracion_y_operatividad_del_plan_de_estudios": "La gestión del plan de estudios estará a cargo del Departamento de Derecho Digital, con una Coordinación Académica y un Comité Curricular que supervisan la calidad y la actualización de las asignaturas; se define el calendario semestral, el plan de créditos y la distribución de asignaturas por ciclo; se implementa un sistema de gestión académica para registro de calificaciones y progresión, con controles de carga horaria y límites; se establece la tutoría y el acompañamiento académico; se define el proceso de homologación, cambios de asignaturas y criterios de permanencia; se contemplan recursos y servicios de apoyo estudiantil, bibliotecas especializadas y laboratorios de tecnología; se vigila el cumplimiento de políticas institucionales, de becas y movilidad; se garantiza la consistencia entre el plan de estudios y los objetivos de aprendizaje; se realizan revisiones periódicas para alinearlo con las necesidades del mercado y la evolución tecnológica.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Se implementará un ciclo de evaluación anual para verificar pertinencia, vigencia y efectividad; se utilizarán instrumentos como rúbricas de evaluación de asignaturas, indicadores de logro de competencias, resultados de exámenes y desempeño profesional; se recogerán encuestas a estudiantes, docentes y empleadores; se analizarán métricas de retención, titulación y inserción laboral; se emitirán informes y Planes de Mejora con acciones correctivas; se revisarán bibliografía y recursos tecnológicos; la revisión actualizará el plan de estudios cada cinco años en coherencia con cambios normativos y tecnológicos.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}, "nivel": "Licenciatura", "activo": true, "nombre": "Licenciatura en Derecho Digital", "creado_en": "2026-02-09T15:04:15.579361+00:00", "plan_hash": "62256c0003b7adb264424a76", "carrera_id": "86a8d3ba-99fb-4e67-a03b-ce2c02d36db9", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Estos textos deben de ser largos, concretos", "descripcionEnfoqueAcademico": "Este programa es un programa educativo que combina fundamentos jurídicos con conocimiento especializado en el entorno digital y tecnológico, abordando los retos legales derivados de la transformación digital en la sociedad con digitalización de servicios, comercios, relaciones laborales y comerciales, así como comunicaciones. Todos estos elementos aumentan el conflicto legales en el ámbito digital."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3627, "total_tokens": 16115, "output_tokens": 12488, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 11136}}, "responseId": "resp_0ce067d662cf