	('2027903b-5f06-4d53-a091-369fd7363eb6', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-04-28 02:39:25.534602+00', 'ACTUALIZACION', 'nivel', '"Diplomado"', '"Maestría"', NULL),
