	('6a4fb8b3-754d-454b-a54f-0e75b89aba9e', '49507442-ca7d-4489-b664-534321617950', NULL, '2026-04-28 11:17:53.153947+00', 'ACTUALIZACION', 'nivel', '"Otro"', '"Diplomado"', NULL),
	('11e143d3-fc32-4d44-a8b1-a41c47d19e30', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-04-28 14:14:32.23803+00', 'ACTUALIZACION', 'nivel', '"Diplomado"', '"Otro"', NULL),
	('b973ba90-9e41-41a7-a1b7-28d4d2968336', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'fines_de_aprendizaje_o_formacion', NULL, '"El programa tiene por finalidad formar profesionales de la educación especializados en el acompañamiento tipo ''sombra'', capaces de intervenir en contextos educativos regulares y de atención especializada mediante prácticas fundamentadas en la evidencia, la colaboración interprofesional y el respeto a los derechos de las personas con discapacidad. Los fines de aprendizaje se articulan en competencias que guían la formación:\n- Analizar los marcos normativos, éticos y teóricos que sustentan la educación especial y la inclusión, con el fin de garantizar intervenciones respetuosas de los derechos y la dignidad de las personas con discapacidad.\n- Identificar las características desarrollo-cognitivas, socioemocionales y comunicativas de estudiantes con diferentes tipos de discapacidad o necesidades educativas especiales, para adecuar estrategias de apoyo.\n- Diseñar planes de acompañamiento individualizados basados en la evaluación formativa, que integren adaptaciones curriculares, apoyos conductuales y mediaciones pedagógicas pertinentes al contexto escolar.\n- Implementar técnicas de observación, registro y evaluación del comportamiento y del progreso académico, utilizando instrumentos estandarizados y protocolos de registro confiables.\n- Colaborar y coordinar con docentes titulares, equipos interdisciplinares y familias para articular apoyos, comunicando hallazgos y proponiendo ajustes en el entorno y la práctica pedagógica.\n- Implementar estrategias de mediación y apoyo que promuevan la participación activa, la autonomía funcional y la inclusión social del alumno dentro del aula regular.\n- Evaluar la eficacia de las intervenciones de sombra mediante indicadores cualitativos y cuantitativos, ajustando las acciones en ciclos de mejora continua.\n- Promover entornos accesibles y diseñar ajustes razonables y recursos didácticos adaptados que favorezcan el aprendizaje y la interacción social.\n- Fomentar actitudes profesionales basadas en la ética, la confidencialidad, el respeto a la diversidad cultural y la toma de decisiones centrada en la persona.\n- Difundir prácticas basadas en evidencia y favorecer la investigación aplicada en contextos escolares para la mejora de modelos de acompañamiento y políticas inclusivas.\n\nEstos fines se desarrollan a través de una secuencia curricular que integra formación teórica avanzada, práctica supervisada en distintos niveles educativos y proyectos integradores que promueven la investigación aplicada en contexto."', NULL),
	('b1399c0e-8440-4826-92d8-bdcb067c5d25', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'clave_del_plan_de_estudios', NULL, '"LLS-LESE-2026"', NULL),
	('6749e872-7c77-4efb-a1bc-b7a23a503cb8', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'diseno_curricular', NULL, '"Rígido"', NULL),
	('abc901f1-7fb9-47d8-a8fe-805f6b0b3569', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'antecedente_academico', NULL, '"Certificado de Bachillerato o equivalente. Preferentemente procedencia de áreas afines como Ciencias de la Educación, Psicología, Trabajo Social, Pedagogía o áreas de ciencias sociales relacionadas con atención a la infancia y discapacidad."', NULL),
	('2598af01-608e-4f2e-8e73-c4e40f6fce00', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'modalidad_educativa', NULL, '"Mixta"', NULL),
	('27217ea8-84f5-4b95-b0de-26203ee62b09', 'dc286072-c649-43aa-8a2f-aa3ef6166647', NULL, '2026-03-04 15:42:54.388936+00', 'ACTUALIZACION_CAMPO', 'area_de_estudio', '"07 Salud (CMPE 2016, campo amplio)"', '"07 Salud (CMPE 2016). Campo de formación específico: Química Farmacéutica, Farmacotecnia, Cosmética y Perfumería (con énfasis en análisis instrumental, regulación y seguridad sanitaria)."', NULL),
