	('b1a142a5-a383-47c8-a2f5-ab34b1cad335', 'fafcf4b2-9d01-469b-bf91-2f338f29e5f5', NULL, '2026-04-28 18:11:30.111935+00', 'CREACION', NULL, NULL, '{"id": "fafcf4b2-9d01-469b-bf91-2f338f29e5f5", "datos": {}, "activo": true, "nombre": "Enfermería (2026)", "creado_en": "2026-04-28T18:11:29.776+00:00", "plan_hash": "e2fd1562fa4825b91971597a", "carrera_id": "21ce004a-2c89-422b-ae7d-675ffcb17365", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {}, "tipo_origen": "MANUAL", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "enfermeria (2026)", "numero_ciclos": 9, "actualizado_en": "2026-04-28T18:11:29.775+00:00", "actualizado_por": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
	('787661a0-1754-4499-a896-5cf55cc99650', '965e8a11-f0d9-439a-b808-d95511ea65f3', NULL, '2026-04-30 16:16:49.169894+00', 'CREACION', NULL, NULL, '{"id": "965e8a11-f0d9-439a-b808-d95511ea65f3", "datos": {"vigencia": "VIGENCIA", "area_de_estudio": "Ingeniería", "perfil_de_egreso": "Al término de la Licenciatura, los egresados serán capaces de:  - Vincular conocimientos fundamentales de matemáticas, ciencias básicas, informática, ingeniería y medicina desde el ámbito de la ingeniería biomédica.  - Coadyuvar en el diseño y la adaptación de equipos y sistemas para la salud.  - Seleccionar, transformar, conservar y producir dispositivos para la atención a la salud.  - Participar en el diseño de unidades físicas de atención a la salud.  - Aplicar técnicas de procesamiento de señales e imágenes.  - Colaborar en la administración de la informática médica.  - Administrar la tecnología biomédica.  - Dirigir áreas de ingeniería biomédica en instituciones hospitalarias.  - Asesorar y participar en la capacitación de usuarios de tecnología biomédica.  - Interactuar éticamente con el personal de salud.  - Diseñar y gestionar proyectos profesionales.  - Incorporar estrategias de autorregulación y comunicación en español e inglés.  - Consolidar una actitud de respeto y valoración cultural.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Es recomendable que el interesado en estudiar la Licenciatura en Ingeniería Biomédica cuente con las siguientes características:  - Preferentemente haber cursado el área de físico-matemáticas de bachillerato.  - Conocimientos en física y matemáticas preuniversitarias.  - Pensamiento lógico-analítico, convergente y divergente.  - Interpretación abstracta de la realidad.  - Trabajo colaborativo y multidisciplinario.  - Solución de problemas desde una perspectiva lógico-matemática.  - Manejo de herramientas y equipos.  - Sensibilidad por problemas y necesidades de la sociedad.", "curso_propedeutico": null, "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato o equivalente", "carga_horaria_a_la_semana": 50, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2013", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Formar profesionistas con saberes, habilidades, actitudes y valores que les permitan incursionar en las diferentes ramas de la profesión, a través de la innovación, aplicación y administración de soluciones tecnológicas viables.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Biomédica", "nombre_autorizado_de_la_institucion": "Universidad La Salle", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": null, "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": null, "propuesta_de_evaluacion_periodica_del_plan_de_estudios": null, "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "MTRO. MARIO ALEJANDRO OLIVARES PORRAZ, SUBDIRECTOR DE RECONOCIMIENTO."}, "activo": true, "nombre": "Ingeniería Biomédica", "creado_en": "2026-04-30T16:16:49.169894+00:00", "plan_hash": "9dcb6f752598cde39c57490e", "carrera_id": "76224caa-1203-4b18-b9df-758f1f9a97fb", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"referencias": {"archivoWordOpenAI": "file-HKtdxQqmtGc2ZzKzEgWXmj"}, "generado_por": "ai-generate-plan", "clonacionPlan": true}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "ingenieria biomedica", "numero_ciclos": 8, "actualizado_en": "2026-04-30T16:16:49.169894+00:00", "actualizado_por": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
