o colaborativo y resolución de problemas.", "curso_propedeutico": null, "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato o equivalente", "carga_horaria_a_la_semana": 50, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2013", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Formar profesionistas con saberes, habilidades, actitudes y valores que les permitan incursionar en diversas ramas de la profesión mediante soluciones tecnológicas viables para mejorar la atención médica.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Biomédica", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "Ocho", "sustento_teorico_del_modelo_curricular": null, "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": null, "propuesta_de_evaluacion_periodica_del_plan_de_estudios": null, "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": ""}, "activo": true, "nombre": "Ingeniería Biomédica", "creado_en": "2026-04-30T17:41:01.359846+00:00", "plan_hash": "f03a540e5c32e38d49bc36fa", "carrera_id": "76224caa-1203-4b18-b9df-758f1f9a97fb", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"referencias": {"archivoWordOpenAI": "file-HKtdxQqmtGc2ZzKzEgWXmj"}, "generado_por": "ai-generate-plan", "clonacionPlan": true}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "ingenieria biomedica", "numero_ciclos": 8, "actualizado_en": "2026-04-30T17:41:01.359846+00:00", "actualizado_por": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
