	('ac45d36c-cc58-4a2c-aa2d-8409306e315a', '87ad7777-db82-49e2-bcdc-54cca0945cfb', NULL, '2026-04-30 18:19:31.804492+00', 'OTRO', 'DELETE', '{"id": "87ad7777-db82-49e2-bcdc-54cca0945cfb", "datos": {"vigencia": "", "area_de_estudio": "Ingeniería y Tecnología", "perfil_de_egreso": "Los egresados serán capaces de: Vincular conocimientos de matemáticas, ciencias básicas, informática, ingeniería y medicina; Coadyuvar en el diseño de equipos de salud; Participar en el diseño de unidades físicas; Aplicar técnicas de procesamiento de señales; Colaborar en la administración de informática médica; Administrar tecnología biomédica; Dirigir áreas de ingeniería biomédica; Asesorar en capacitación para el manejo de tecnología biomédica; Interactuar éticamente con el personal de salud; Diseñar proyectos vinculados a su profesión; Incorporar estrategias de comunicación en su práctica profesional; Consolidar respeto y valoración por la diversidad.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Se recomienda que el interesado cuente con: Antecedentes académicos de físico-matemáticas; Conocimientos en física y matemáticas preuniversitarias; Disposición para el pensamiento lógico-analítico, trabajo colaborativo, solución de problemas, manejo de herramientas y construcción de soluciones tecnológicas; Actitudes de sensibilidad social, ética, responsabilidad y perspectiva comunitaria.", "curso_propedeutico": "", "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato o equivalente", "carga_horaria_a_la_semana": 50, "programa_de_investigacion": "", "clave_del_plan_de_estudios": "2013", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Formar profesionistas capaces de innovar, aplicar y administrar soluciones tecnológicas en el ámbito de la salud, interactuando en equipos multidisciplinarios para mejorar la atención médica.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Biomédica", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": "", "justificacion_de_la_propuesta_curricular": "", "administracion_y_operatividad_del_plan_de_estudios": "", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "MTRO. MARIO ALEJANDRO OLIVARES PORRAZ, SUBDIRECTOR DE RECONOCIMIENTO"}, "activo": true, "nombre": "Ingeniería Biomédica", "creado_en": "2026-04-30T17:48:35.729515+00:00", "plan_hash": "52f6b613d9e1f230e632a9b0", "carrera_id": "76224caa-1203-4b18-b9df-758f1f9a97fb", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"referencias": {"archivoWordOpenAI": "file-LTjfivcVJbQ9SSxZXJRogV"}, "generado_por": "ai-generate-plan", "clonacionPlan": true}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "ingenieria biomedica", "numero_ciclos": 8, "actualizado_en": "2026-04-30T17:48:35.729515+00:00", "actualizado_por": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL, NULL),
	('d735174d-5456-4f68-9876-0aae3dbb0a84', '8c17ae7b-50b0-48a0-992f-cc01283ecb78', NULL, '2026-04-30 18:20:51.815375+00', 'CREACION', NULL, NULL, '{"id": "8c17ae7b-50b0-48a0-992f-cc01283ecb78", "datos": {"vigencia": "", "area_de_estudio": "Ingeniería", "perfil_de_egreso": "Al término de la Licenciatura, los egresados serán capaces de:\n· Vincular conocimientos fundamentales de matemáticas, ciencias básicas, informática, ingeniería y medicina desde el ámbito de la ingeniería biomédica, para incidir en la calidad de los servicios del Sistema de Salud.\n· Coadyuvar en el diseño y la adaptación de equipos y sistemas para la salud, así como en la innovación y conservación de la tecnología médica para la atención integral de la población.\n· Seleccionar, transformar, conservar y producir dispositivos tales como instrumentos, equipos, aparatos o accesorios diversos para el eficiente funcionamiento del proceso de atención a la salud, contribuyendo a la preservación del medio ambiente.\n· Participar, bajo principios éticos, en el diseño de unidades físicas de atención a la salud, así como en la elaboración de la normatividad técnica para su construcción y equipamiento, estableciendo criterios y estándares óptimos que apoyen la gestión sostenible de recursos.\n· Aplicar técnicas de procesamiento de señales e imágenes, para coadyuvar en el diagnóstico médico y en la telemedicina.\n· Colaborar en la administración de la informática médica, considerando estándares nacionales e internacionales, para el aprovechamiento integral de recursos de entidades nosológicas.\n· Administrar la tecnología biomédica considerando su planeación, adquisición, mantenimiento y evaluación para mejorar la eficiencia y eficacia de la atención a la salud.\n· Dirigir las áreas de ingeniería biomédica de instituciones hospitalarias aplicando técnicas modernas y vinculando acciones administrativas, médicas y de mejora.\n· Asesorar y participar en la capacitación de los usuarios para el manejo adecuado de la tecnología biomédica.\n· Interactuar de manera profesional y ética con el personal que brinda los servicios de salud, proponiendo soluciones multidisciplinarias en el campo de la ingeniería biomédica con actitud de cooperación y respeto.\n· Diseñar y gestionar proyectos vinculados a su desarrollo profesional ocupacional, con actitud emprendedora e innovadora, bajo un enfoque de sustentabilidad y de responsabilidad social, a partir del trabajo multidisciplinar y colaborativo, considerando las características de la sociedad actual a nivel local y global.\n· Incorporar en su práctica profesional, la utilización de estrategias de autorregulación y comunicación eficaz en español e inglés, así como las TIC como herramientas para la gestión de información y la actualización permanente en su campo disciplinar, con el fin de favorecer el intercambio de ideas en contextos multidisciplinarios tanto académicos como profesionales.\n· Consolidar una actitud de respeto y valoración por sí mismo, los demás y diversas culturas incluida la propia, así como contraer un compromiso de servicio a nivel personal y profesional hacia la sociedad actual, a partir de la reflexión y definición de sus posturas con respecto a los valores trascendentes de la existencia humana.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Es recomendable que el interesado en estudiar la Licenciatura en Ingeniería Biomédica cuente con las siguientes características:\nAntecedentes Académicos\n· Preferentemente haber cursado el área de físico-matemáticas de bachillerato\nConocimientos\n· Física y matemáticas preuniversitarias\nDisposición para (habilidades y destrezas):\n· El pensamiento lógico-analítico\n· El pensamiento convergente y divergente\n· La interpretación abstracta de la realidad\nDisposición para (habilidades y destrezas):\n· El trabajo colaborativo y multidisciplinario\n· La solución de problemas desde una perspectiva reflexiva y lógico-matemática\n· El manejo de herramientas, máquinas, materiales y equipos\n· La construcción de soluciones que integren tecnologías, con el apoyo de herramientas computacionales\nActitudes y Valores\n· Sensibilidad por los problemas y necesidades de la sociedad\n· Consideración de principios éticos y de respeto\n· Responsabilidad y autodisciplina\n· Perspectiva comunitaria", "curso_propedeutico": null, "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato o equivalente", "carga_horaria_a_la_semana": 50, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2013", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Formar profesionistas con saberes, habilidades, actitudes y valores que les permitan incursionar en las diferentes ramas de la profesión, a través de la innovación, aplicación y administración de soluciones tecnológicas viables que coadyuven a mejorar la atención médica de la población; e interactuar en equipos multidisciplinarios para incidir en la calidad de los servicios del Sistema de Salud, todo ello sustentado en principios científicos, bioéticos y humanistas.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Biomédica", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "8 ciclos", "sustento_teorico_del_modelo_curricular": null, "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": null, "propuesta_de_evaluacion_periodica_del_plan_de_estudios": null, "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "MTRO. MARIO ALEJANDRO OLIVARES PORRAZ, SUBDIRECTOR DE RECONOCIMIENTO, DIRECCIÓN DE INSTITUCIONES PARTICULARES DE EDUCACIÓN SUPERIOR, S.E.P."}, "activo": true, "nombre": "Ingeniería Biomédica", "creado_en": "2026-04-30T18:20:51.815375+00:00", "plan_hash": "80096a480deb3eaf7f4c084d", "carrera_id": "76224caa-1203-4b18-b9df-758f1f9a97fb", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"referencias": {"archivoWordOpenAI": "file-LTjfivcVJbQ9SSxZXJRogV"}, "generado_por": "ai-generate-plan", "clonacionPlan": true}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "ingenieria biomedica", "numero_ciclos": 8, "actualizado_en": "2026-04-30T18:20:51.815375+00:00", "actualizado_por": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
